import React, { createContext, useContext, useState, useCallback, useRef } from 'react';
import { createPortal } from 'react-dom';
import { X, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';

export type ToastType = 'success' | 'error' | 'loading' | 'info';

interface Toast {
  id: string;
  message: string;
  type: ToastType;
}

interface ToastContextType {
  addToast: (message: string, type: ToastType, duration?: number) => void;
  removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [toasts, setToasts] = useState<Toast[]>([]);

  // Use a ref to keep track of timeouts so we can clear them (cleanup)
  const timeoutsRef = useRef<Record<string, NodeJS.Timeout>>({});

  const removeToast = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
    if (timeoutsRef.current[id]) {
      clearTimeout(timeoutsRef.current[id]);
      delete timeoutsRef.current[id];
    }
  }, []);

  const addToast = useCallback(
    (message: string, type: ToastType, duration = 3000) => {
      const id = Math.random().toString(36).substr(2, 9);
      setToasts((prev) => [...prev, { id, message, type }]);

      if (type !== 'loading') {
        timeoutsRef.current[id] = setTimeout(() => {
          removeToast(id);
        }, duration);
      }
    },
    [removeToast],
  );

  return (
    <ToastContext.Provider value={{ addToast, removeToast }}>
      {children}
      {createPortal(
        <div className="fixed top-4 right-4 z-50 flex flex-col gap-2">
          {toasts.map((toast) => (
            <div
              key={toast.id}
              className={`
                                flex items-center gap-3 px-4 py-3 rounded-xl shadow-2xl border min-w-[300px] animate-in slide-in-from-right
                                ${toast.type === 'success' ? 'bg-emerald-900/90 border-emerald-500 text-emerald-100' : ''}
                                ${toast.type === 'error' ? 'bg-red-900/90 border-red-500 text-red-100' : ''}
                                ${toast.type === 'loading' ? 'bg-blue-900/90 border-blue-500 text-blue-100' : ''}
                                ${toast.type === 'info' ? 'bg-slate-800/90 border-slate-500 text-slate-100' : ''}
                            `}
            >
              {toast.type === 'success' && <CheckCircle className="w-5 h-5 text-emerald-400" />}
              {toast.type === 'error' && <AlertCircle className="w-5 h-5 text-red-400" />}
              {toast.type === 'loading' && (
                <Loader2 className="w-5 h-5 text-blue-400 animate-spin" />
              )}

              <p className="flex-1 font-medium text-sm">{toast.message}</p>

              <button
                onClick={() => removeToast(toast.id)}
                className="opacity-70 hover:opacity-100 hover:bg-white/10 rounded p-1 transition-all"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>,
        document.body,
      )}
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const context = useContext(ToastContext);
  if (!context) {
    throw new Error('useToast must be used within a ToastProvider');
  }
  return context;
};

import { useState, useEffect, useRef } from 'react';
import { ENTITY_REGISTRY } from '../config/EntityRegistry';
import { UniversalService } from '../services/api';
import { Plus, Trash2, Edit, Upload, FileText, Search, X, Check, Loader2 } from 'lucide-react';
import * as XLSX from 'xlsx';

interface Props {
  entityKey: string;
}

const UniversalResourceManager = ({ entityKey }: Props) => {
  const config = ENTITY_REGISTRY[entityKey];
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [searchTerm, setSearchTerm] = useState('');

  // Edit Modal State
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null); // Null = Create, Object = Edit
  const [formLoading, setFormLoading] = useState(false);

  useEffect(() => {
    if (config) {
      loadData();
    }
  }, [entityKey, page]);

  const loadData = async () => {
    setLoading(true);
    try {
      const res = await UniversalService.list(config.apiPath, page, 50);

      // Safety guard: If API returns unexpected structure or 404 handled by interceptor as null/generic error
      if (res && res.data) {
        setData(res.data || []);
        setTotal((res as { data: unknown[]; meta?: { total?: number } }).meta?.total ?? 0);
      } else {
        console.warn('ÔÜá´©Å [UniversalResourceManager] Received invalid data structure:', res);
        setData([]);
        setTotal(0);
      }
    } catch (error: any) {
      console.error('Ôøö [UniversalResourceManager] Critical Load Error:', error);

      // Check for 404 or specific error to stop retrying if necessary
      // The useEffect logic [entityKey, page] doesn't natively loop unless something resets page/entityKey
      // but if the parent component unmounts/remounts due to error boundary, it could loop.

      if (String(error).includes('404')) {
        console.error('­ƒøæ Backend route missing. Stopping.');
      }
      setData([]); // Ensure no undefined data crashes filter logic
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (item: any) => {
    if (!config.actions.delete) return;

    const isMasterRoute = entityKey === 'MASTER_ROUTES';
    const itemName = item.line || item.name || item.id;

    // Double confirmation for critical data
    if (isMasterRoute) {
      if (
        !window.confirm(
          `ÔÜá´©Å ESTA ACCI├ôN ES IRREVERSIBLE. ┬┐Realmente desea ELIMINAR LA L├ìNEA ${itemName}?`,
        )
      )
        return;
      if (
        !window.confirm(
          `┬┐CONFIRMA borrar todos los trazados, paradas y alertas asociadas a la L├ìNEA ${itemName}?`,
        )
      )
        return;
    } else {
      if (!window.confirm(`┬┐Seguro que desea eliminar el registro "${itemName}"?`)) return;
    }

    try {
      await UniversalService.delete(config.apiPath, item.id);
      loadData();
    } catch (error) {
      alert('Error al eliminar');
    }
  };

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!window.confirm(`┬┐Confirmar importaci├│n masiva desde ${file.name}?`)) {
      e.target.value = '';
      return;
    }

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const jsonData = XLSX.utils.sheet_to_json(ws);

        if (jsonData.length === 0) {
          alert('El archivo est├í vac├¡o');
          return;
        }

        await UniversalService.import(config.apiPath, jsonData);
        alert(
          `┬íImportaci├│n Exitosa!\n\nSe han procesado ${jsonData.length} registros correctamente.`,
        );
        loadData();
      } catch (error: any) {
        console.error('IMPORT ERROR:', error);
        const errorMsg = error.message || String(error);
        alert(
          `ÔØî ERROR EN IMPORTACI├ôN:\n\n${errorMsg}\n\nVerifique que las columnas del Excel coincidan con los requisitos del sistema.`,
        );
      } finally {
        setLoading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleExportExcel = () => {
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Datos');
    XLSX.writeFile(wb, `${config.pdfTitle || entityKey}.xlsx`);
  };

  const handleOpenEdit = (item: any = null) => {
    setEditingItem(item);
    setIsEditModalOpen(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormLoading(true);
    // Extract form data
    const formData = new FormData(e.target as HTMLFormElement);
    const rawData: any = {};

    config.columns.forEach((col) => {
      if (col.editable) {
        const val = formData.get(col.key);
        // Simple type conversion
        if (col.type === 'number') {
          rawData[col.key] = Number(val);
        } else {
          rawData[col.key] = val;
        }
      }
    });

    try {
      if (editingItem) {
        // Update
        await UniversalService.update(config.apiPath, editingItem.id, rawData);
      } else {
        // Create
        await UniversalService.create(config.apiPath, rawData);
      }
      setIsEditModalOpen(false);
      loadData();
    } catch (error) {
      console.error(error);
      alert('Error al guardar: ' + String(error));
    } finally {
      setFormLoading(false);
    }
  };

  if (!config) {
    return (
      <div className="p-10 text-center text-red-500">
        Configuraci├│n no encontrada para la entidad: {entityKey}
      </div>
    );
  }

  const filteredData = data.filter((item) =>
    Object.values(item).some((val) => String(val).toLowerCase().includes(searchTerm.toLowerCase())),
  );

  // Duplicate removed

  return (
    <div className="space-y-6 animate-fade-in-up">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleImport}
        className="hidden"
        accept=".xlsx,.xls,.csv"
      />
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
        <div>
          <h1 className="text-2xl font-bold text-white mb-2 flex items-center gap-3">
            {config.labels.title}
            <span className="text-xs px-2 py-1 bg-indigo-500/20 text-indigo-400 rounded-full border border-indigo-500/20">
              Total: {total}
            </span>
          </h1>
          <p className="text-slate-400 text-sm">
            Administraci├│n centralizada de {config.labels.plural.toLowerCase()}
          </p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="relative">
            <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
            <input
              type="text"
              placeholder="Buscar..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="bg-slate-900 border border-slate-700 rounded-xl pl-9 pr-4 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 outline-none w-48"
            />
          </div>

          {config.actions.export && (
            <div className="flex gap-2">
              <button
                onClick={handleExportExcel}
                className="p-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 rounded-xl border border-emerald-500/20 transition-colors"
                title="Exportar Excel"
              >
                <FileText className="w-5 h-5" />
              </button>
            </div>
          )}

          {config.actions.import && (
            <button
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-xl transition-colors font-medium text-sm"
            >
              <Upload className="w-4 h-4" />
              Importar Excel
            </button>
          )}

          {config.actions.create && (
            <button
              onClick={() => handleOpenEdit(null)}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl transition-all shadow-lg shadow-indigo-900/20 font-bold"
            >
              <Plus className="w-5 h-5" />
              Nuevo {config.labels.singular}
            </button>
          )}
        </div>
      </div>

      {/* Content Table */}
      <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden shadow-xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-900/50 text-slate-400 text-xs uppercase tracking-wider font-semibold">
              <tr>
                {config.columns
                  .filter((c) => !c.hiddenInTable)
                  .map((col) => (
                    <th key={col.key} className="p-4 border-b border-slate-700">
                      {col.label}
                    </th>
                  ))}
                <th className="p-4 border-b border-slate-700 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-700/50">
              {loading ? (
                <tr>
                  <td colSpan={config.columns.length + 1} className="p-8 text-center">
                    <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
                  </td>
                </tr>
              ) : filteredData.length === 0 ? (
                <tr>
                  <td
                    colSpan={config.columns.length + 1}
                    className="p-8 text-center text-slate-500"
                  >
                    No hay {config.labels.plural.toLowerCase()} disponibles.
                  </td>
                </tr>
              ) : (
                filteredData.map((row) => (
                  <tr key={row.id} className="hover:bg-slate-700/30 transition-colors group">
                    {config.columns
                      .filter((c) => !c.hiddenInTable)
                      .map((col) => (
