      dismiss(tId);
      showError(`Error al crear reporte: ${e.message}`);
    }
  };

  if (!['Admin', 'SuperAdmin', 'Inspector'].includes(user?.role || '')) return null;

  return (
    <div
      className={clsx(
        'fixed bottom-0 left-0 right-0 z-50 transition-all duration-300 ease-out',
