          setToken(null);
          setUser(null);
        }
      } catch (error) {
        console.error('ÔØî [AuthContext] Critical Auth Error:', error);
        setToken(null);
        setUser(null);
      } finally {
        // ­ƒöô LIFT THE WALL: Whether success or failure, we are done checking.
        setInitializing(false);
      }
    });

    return () => unsubscribe();
  }, []);

  const login = (newToken: string, newUser: User) => {
    setToken(newToken);
    setUser(newUser);
  };

  const logout = () => {
    auth.signOut();
    setToken(null);
    setUser(null);
    window.location.assign('/login');
  };

  // Ôøö BLOCKED STATE RENDER
  if (initializing) {
    return (
      <div className="min-h-screen w-full flex flex-col items-center justify-center bg-slate-950 text-white">
        <div className="w-16 h-16 border-4 border-primary-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <h2 className="text-xl font-bold tracking-tight">Iniciando Sistema UCOT...</h2>
        <p className="text-slate-500 text-sm mt-2">Verificando credenciales seguras</p>
      </div>
    );
  }

  return (
    <AuthContext.Provider
      value={{
        user,
        token,
        isAuthenticated: !!user && !!token,
        isLoading: initializing,
        login,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

