/**
 * useFleetRealtime ÔÇö Hook GPS en tiempo real
 * ===========================================
 * Escucha viajes_activos en Firestore y retorna la flota activa actualizada.
 * Usado por FleetMonitorModule, CEODashboard y cualquier widget de mapa.
 *
 * D├ôNDE COLOCAR: frontend/src/hooks/useFleetRealtime.ts
 *
 * USO:
 *   const { vehiculos, total, loading } = useFleetRealtime();
 *   const { vehiculos } = useFleetRealtime({ soloEmpresa: 'UCOT', inactividadMin: 10 });
 */

import { useState, useEffect, useCallback } from 'react';
import { collection, onSnapshot, type DocumentData } from 'firebase/firestore';
import { db } from '../config/firebase';

// ÔöÇÔöÇÔöÇ Tipos ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface VehiculoEnMapa {
  id: string;
  cocheId: string;
  empresa: string;
  codigoLinea: string;
  conductorNombre: string;
  lat: number;
  lng: number;
  velocidad: number | null;
  estado: string;
  updatedAtMs: number;
  hacieCuantoMin: number;
}

export interface UseFleetRealtimeOptions {
  soloEmpresa?: string;       // Filtrar por empresa, ej: 'UCOT'
  inactividadMin?: number;    // Descartar veh├¡culos inactivos hace N min (default: 15)
  habilitado?: boolean;       // Pausar el listener si false
}

export interface UseFleetRealtimeResult {
  vehiculos: VehiculoEnMapa[];
  total: number;
  totalUCOT: number;
  totalCompetencia: number;
  loading: boolean;
  error: string | null;
  ultimaActualizacion: Date | null;
  refrescar: () => void;
}

// ÔöÇÔöÇÔöÇ Hook ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const COL_VIAJES = 'viajes_activos';

export function useFleetRealtime(
  opciones: UseFleetRealtimeOptions = {},
): UseFleetRealtimeResult {
  const {
    soloEmpresa,
    inactividadMin = 15,
    habilitado = true,
  } = opciones;

  const [vehiculos, setVehiculos] = useState<VehiculoEnMapa[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [ultimaActualizacion, setUltimaActualizacion] = useState<Date | null>(null);
  const [refreshKey, setRefreshKey] = useState(0);

  const refrescar = useCallback(() => setRefreshKey((k) => k + 1), []);

  useEffect(() => {
    if (!habilitado) {
      setLoading(false);
      return;
    }

    setLoading(true);
    setError(null);

    const colRef = collection(db, COL_VIAJES);
    const inactividadMs = inactividadMin * 60 * 1000;

    const unsubscribe = onSnapshot(
      colRef,
      (snapshot) => {
        const ahora = Date.now();
        const cutoff = ahora - inactividadMs;

        const lista: VehiculoEnMapa[] = [];

        snapshot.docs.forEach((docSnap: DocumentData) => {
          const data = docSnap.data() as Record<string, unknown>;

          // Filtrar inactivos
          const updatedAtMs = toMillis(data.updatedAt);
          if (updatedAtMs < cutoff) return;

          // Filtrar por empresa si se especific├│
          if (soloEmpresa && data.empresa !== soloEmpresa) return;

          // Extraer posici├│n
          const pos = data.posicion as { latitude?: number; longitude?: number } | undefined;
          if (!pos || typeof pos.latitude !== 'number' || typeof pos.longitude !== 'number') return;

          const hacieCuantoMin = Math.floor((ahora - updatedAtMs) / 60000);

          lista.push({
            id: docSnap.id,
            cocheId: String(data.cocheId ?? docSnap.id),
            empresa: String(data.empresa ?? 'UCOT'),
            codigoLinea: String(data.codigoLinea ?? 'ÔÇö'),
            conductorNombre: String(data.conductorNombre ?? 'Conductor'),
            lat: pos.latitude,
            lng: pos.longitude,
            velocidad: data.velocidad != null ? Number(data.velocidad) : null,
            estado: String(data.estado ?? 'en_servicio'),
            updatedAtMs,
            hacieCuantoMin,
          });
        });

        // Ordenar por empresa UCOT primero, luego por l├¡nea
        lista.sort((a, b) => {
          if (a.empresa === 'UCOT' && b.empresa !== 'UCOT') return -1;
          if (a.empresa !== 'UCOT' && b.empresa === 'UCOT') return 1;
          return a.codigoLinea.localeCompare(b.codigoLinea);
        });

        setVehiculos(lista);
        setLoading(false);
        setUltimaActualizacion(new Date());
        setError(null);
      },
      (err) => {
        console.error('[useFleetRealtime] Error Firestore:', err.message);
        setError(err.message);
        setLoading(false);
      },
    );

    return () => unsubscribe();
  }, [habilitado, inactividadMin, soloEmpresa, refreshKey]);

  const totalUCOT = vehiculos.filter((v) => v.empresa === 'UCOT').length;
  const totalCompetencia = vehiculos.filter((v) => v.empresa !== 'UCOT').length;

  return {
    vehiculos,
    total: vehiculos.length,
    totalUCOT,
    totalCompetencia,
    loading,
    error,
    ultimaActualizacion,
    refrescar,
  };
}

// ÔöÇÔöÇÔöÇ Helper ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function toMillis(updatedAt: unknown): number {
  if (!updatedAt) return 0;
  const ts = updatedAt as { toMillis?: () => number; seconds?: number };
  if (typeof ts.toMillis === 'function') return ts.toMillis();
  if (typeof ts.seconds === 'number') return ts.seconds * 1000;
  return 0;
}

/**
 * useKPIs ÔÇö KPIs en tiempo real para el CEO Dashboard
 * =====================================================
 * Combina datos de Firestore y calcula los KPIs operativos clave.
 *
 * D├ôNDE COLOCAR: frontend/src/hooks/useKPIs.ts
 *
 * USO:
 *   const { kpis, loading } = useKPIs();
 */

import { useState, useEffect } from 'react';
import {
  collection,
  onSnapshot,
  query,
  where,
  getDocs,
} from 'firebase/firestore';
import { db } from '../config/firebase';

// ÔöÇÔöÇÔöÇ Tipos ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface KPIs {
  // Flota
  vehiculosTotal: number;
  vehiculosActivos: number;
  vehiculosEnServicioGPS: number;
  flotaActivaPct: number;

  // Puntualidad
  puntualidadPct: number | null;
  serviciosConAtraso: number;
  atrasoPromedioMin: number;

  // Operativo del d├¡a
  serviciosHoy: number;
  alertasActivas: number;
  mantenimientosPendientes: number;

  // Financiero (si hay datos)
  boletosHoy: number | null;
  ingresosHoy: number | null;          // En pesos UY

  // Metadata
  fechaCalculo: string;
  horaCalculo: string;
}

const KPI_INICIAL: KPIs = {
  vehiculosTotal: 0,
  vehiculosActivos: 0,
  vehiculosEnServicioGPS: 0,
  flotaActivaPct: 0,
  puntualidadPct: null,
  serviciosConAtraso: 0,
  atrasoPromedioMin: 0,
  serviciosHoy: 0,
  alertasActivas: 0,
  mantenimientosPendientes: 0,
  boletosHoy: null,
  ingresosHoy: null,
  fechaCalculo: '',
  horaCalculo: '',
};

// ÔöÇÔöÇÔöÇ Hook ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export function useKPIs(autoRefreshMs = 60_000) {
  const [kpis, setKpis] = useState<KPIs>(KPI_INICIAL);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const today = new Date().toISOString().split('T')[0];
  const INACTIVIDAD_MS = 15 * 60 * 1000;

  // Listener en tiempo real para viajes_activos (GPS)
  useEffect(() => {
    const unsubGps = onSnapshot(
      collection(db, 'viajes_activos'),
      async (gpsSnap) => {
        try {
          const ahora = Date.now();
          const cutoff = ahora - INACTIVIDAD_MS;

          const gpsActivos = gpsSnap.docs.filter((d) => {
            const ts = d.data().updatedAt as { toMillis?: () => number } | undefined;
            return ts && typeof ts.toMillis === 'function' && ts.toMillis() > cutoff;
          }).length;

          // Obtener resto de datos en paralelo
          const [vehiculosSnap, estadosSnap, alertasSnap, mantenimientoSnap] =
            await Promise.all([
              getDocs(collection(db, 'vehicles')),
              getDocs(
                query(collection(db, 'servicio_estado'), where('fecha', '==', today)),
              ),
              getDocs(
                query(collection(db, 'road_alerts'), where('estado', '==', 'activa')),
              ),
              getDocs(
                query(collection(db, 'maintenance'), where('estado', '==', 'pendiente')),
              ),
            ]);

          // Flota
          const total = vehiculosSnap.size;
          const activos = vehiculosSnap.docs.filter((d) =>
            !/mantenimiento|taller|paralizado|baja/i.test(String(d.data().status ?? '')),
          ).length;

          // Puntualidad
          const estados = estadosSnap.docs.map((d) => d.data());
          const conAtraso = estados.filter((e) => e.atrasoMinutos != null);
          const puntuales = conAtraso.filter((e) => (e.atrasoMinutos ?? 0) <= 3).length;
          const puntualidadPct =
            conAtraso.length > 0
              ? Math.round((puntuales / conAtraso.length) * 100)
              : null;
          const atrasoTotal = conAtraso.reduce(
            (s, e) => s + Number(e.atrasoMinutos ?? 0), 0,
          );
          const atrasoPromedio =
            conAtraso.length > 0
              ? Math.round(atrasoTotal / conAtraso.length)
              : 0;

          const now = new Date();
          setKpis({
            vehiculosTotal: total,
            vehiculosActivos: activos,
            vehiculosEnServicioGPS: gpsActivos,
            flotaActivaPct: total > 0 ? Math.round((activos / total) * 100) : 0,
            puntualidadPct,
            serviciosConAtraso: conAtraso.length - puntuales,
            atrasoPromedioMin: atrasoPromedio,
            serviciosHoy: estados.length,
            alertasActivas: alertasSnap.size,
            mantenimientosPendientes: mantenimientoSnap.size,
            boletosHoy: null,
            ingresosHoy: null,
            fechaCalculo: today,
            horaCalculo: now.toTimeString().slice(0, 5),
          });

          setLoading(false);
          setError(null);
        } catch (err) {
          console.error('[useKPIs] Error:', err);
          setError(err instanceof Error ? err.message : 'Error cargando KPIs');
          setLoading(false);
        }
      },
      (err) => {
        setError(err.message);
        setLoading(false);
      },
    );

    return () => unsubGps();
  }, [today]);

  return { kpis, loading, error };
}

