export const useVersionCheck = () => {
  const [isUpdating, setIsUpdating] = useState(false);

  useEffect(() => {
    const checkVersion = async () => {
      try {
        // Agregar timestamp para evitar cach├® del navegador (especialmente en Brave/Safari)
        const res = await fetch(`/version.json?t=${Date.now()}`, { cache: 'no-store' });
        if (!res.ok) return;

        const data = await res.json();
        const serverVersion = data.version;
        const localVersion = localStorage.getItem('app_version');

        // Si es la primera vez (no hay localVersion), guardamos y no hacemos nada
        if (!localVersion) {
          localStorage.setItem('app_version', serverVersion);
          return;
        }

        // Si las versiones difieren, forzamos actualizaci├│n
        if (serverVersion !== localVersion) {
          console.log(`­ƒÜÇ New Version Detected: ${serverVersion} (Local: ${localVersion})`);

          // ­ƒÄ« SIMULATION BYPASS: In Sim mode, just show UI but don't wipe data aggressively
          const isSim = sessionStorage.getItem('TRANSFORMA_SIMULATION_MODE') === 'true';

          setIsUpdating(true);

          // 1. Limpiar Service Workers antiguos
          if ('serviceWorker' in navigator) {
            const registrations = await navigator.serviceWorker.getRegistrations();
            for (const registration of registrations) {
              await registration.unregister();
            }
          }

          // 2. Limpiar Cach├® de la Aplicaci├│n
          if ('caches' in window) {
            const keys = await caches.keys();
            await Promise.all(keys.map((key) => caches.delete(key)));
          }

          // 3. Actualizar Referencia
          localStorage.setItem('app_version', serverVersion);

          // 4. Recargar P├ígina (dar tiempo a la animaci├│n de VersionGuard)
          setTimeout(() => {
            window.location.reload();
          }, 3500);
        }
      } catch (error) {
        console.error('Version check failed:', error);
      }
    };

    // Chequear al inicio y cada 60 segundos
    checkVersion();
    const interval = setInterval(checkVersion, 60000);
    return () => clearInterval(interval);
  }, []);

  return { isUpdating };
};

