export default AdminRRHH;

import { useState, useEffect } from 'react';
import { ShiftService, type Shift } from '../../services/api';
import { PDFService } from '../../services/pdf';
import ShiftCard from '../../components/ShiftCard';
import EditShiftModal from '../../components/EditShiftModal';
import AssignShiftModal from '../../components/AssignShiftModal';
import { Search, Filter, FileText, Loader2, AlertCircle } from 'lucide-react';
import clsx from 'clsx';

const AdminShifts = () => {
  const [activeTab, setActiveTab] = useState<'Created' | 'Public' | 'Assigned'>('Created');
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [shifts, setShifts] = useState<Shift[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [editingShift, setEditingShift] = useState<Shift | null>(null);
  const [assigningShiftId, setAssigningShiftId] = useState<number | null>(null);
  const [confirmAction, setConfirmAction] = useState<{
    type: 'delete' | 'reject';
    id: number;
  } | null>(null);

  useEffect(() => {
    loadShifts();
  }, [selectedDate]); // Reload when date changes

  const loadShifts = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await ShiftService.getAll(selectedDate);
      setShifts(data || []);
      return data || [];
    } catch (error) {
      console.error('Error loading shifts', error);
      setError('No se pudieron cargar los turnos. Por favor, verifique su conexi├│n.');
      setShifts([]);
      return [];
    } finally {
      setIsLoading(false);
    }
  };

  const handleAction = async (action: string, id: number | string) => {
    const shift = shifts.find((s) => s.id === id);
    if (!shift) return;

    // If it's a planned shift (string ID), some actions might need creation first
    if (typeof id === 'string') {
      if (action === 'assign' || action === 'edit' || action === 'approve') {
        // For now, we'll alert that it's a planned shift.
        // In a real scenario, we might "solidify" it by creating the shift record first.
        alert(
          'Este es un turno programado por rotaci├│n. Para modificarlo, primero gu├írdelo como turno real.',
        );
        return;
      }
      return;
    }

    if (action === 'approve') {
      if (shift.transformaFacil) {
        const discount = prompt(
          'Este turno es TransForma- (A Canje). Ingrese el monto del descuento para el administrador:',
          '200',
        );
        if (discount !== null) {
          shift.transformaFacilDiscount = Number(discount);
          shift.totalValue =
            Number(shift.totalValue ?? 0) - Number(shift.transformaFacilDiscount ?? 0); // Apply discount to total
        }
      }
      await ShiftService.publish(id);
      alert('Turno aprobado y publicado.');
      loadShifts();
    }

    if (action === 'reject') {
      setConfirmAction({ type: 'reject', id });
    }

    if (action === 'delete') {
      setConfirmAction({ type: 'delete', id });
    }

    if (action === 'edit') {
      setEditingShift(shift);
    }

    if (action === 'assign') {
      setAssigningShiftId(id);
    }
  };

  const handleAssignShift = async (userId: number) => {
    if (assigningShiftId) {
      try {
        await ShiftService.assign(assigningShiftId, userId);
        alert('Turno asignado exitosamente.');
        loadShifts();
      } catch (error: any) {
        alert(error.message || 'Error al asignar el turno.');
      }
    }
  };

  const executeConfirmAction = async () => {
    if (!confirmAction) return;

    try {
      await ShiftService.delete(confirmAction.id);
      alert(
        confirmAction.type === 'reject'
          ? 'Turno rechazado y eliminado.'
          : 'Turno eliminado exitosamente.',
      );
      loadShifts();
    } catch (error) {
      console.error('Error deleting shift:', error);
      alert('Error al procesar la solicitud.');
    } finally {
      setConfirmAction(null);
    }
  };

  // Search State
  const [searchText, setSearchText] = useState('');

  const filteredShifts = shifts.filter((s) => {
    const matchesTab = s.status === activeTab;
    const search = searchText.toLowerCase();

    if (!searchText) return matchesTab;

    const sn = s as Record<string, unknown>;
    const matchesSearch =
      String(sn.serviceNumber ?? '')
        .toLowerCase()
        .includes(search) ||
      String(sn.carNumber ?? '')
        .toLowerCase()
        .includes(search) ||
      String(sn.assigneeName ?? '')
        .toLowerCase()
        .includes(search) ||
      String(sn.assigneeInternalNumber ?? '').includes(search) ||
      String(sn.creatorName ?? '')
        .toLowerCase()
        .includes(search) ||
      String(sn.line ?? '')
        .toLowerCase()
        .includes(search);

    return matchesTab && matchesSearch;
  });

  const TabButton = ({ name, label, count }: { name: string; label: string; count: number }) => (
    <button
      onClick={() => setActiveTab(name as any)}
      className={clsx(
        'pb-4 px-4 text-sm font-medium transition-all relative',
        activeTab === name ? 'text-primary-400' : 'text-slate-400 hover:text-white',
      )}
    >
      <span>{label}</span>
      <span
        className={clsx(
          'ml-2 text-xs py-0.5 px-2 rounded-full',
          activeTab === name ? 'bg-primary-500/20 text-primary-300' : 'bg-slate-800 text-slate-500',
        )}
      >
        <span>{count}</span>
      </span>
      {activeTab === name && (
        <span className="absolute bottom-0 left-0 w-full h-0.5 bg-primary-500 rounded-t-full"></span>
      )}
    </button>
  );

  // State for PDF Automation
  // State for PDF Automation (Refactored for Stability)
  const [autoDownload, setAutoDownload] = useState(false);
  const [downloadInterval, setDownloadInterval] = useState(60); // minutes
  const lastDownloadRef = useState({ time: Date.now() })[0]; // Mutable ref-like object or strictly useRef

  // Load settings
  useEffect(() => {
    const storedAuto = localStorage.getItem('admin_pdf_auto');
    const storedInterval = localStorage.getItem('admin_pdf_interval');
    if (storedAuto) setAutoDownload(storedAuto === 'true');
    if (storedInterval) setDownloadInterval(Number(storedInterval));
  }, []);

  // Save settings
  useEffect(() => {
    localStorage.setItem('admin_pdf_auto', String(autoDownload));
    localStorage.setItem('admin_pdf_interval', String(downloadInterval));
  }, [autoDownload, downloadInterval]);

  // Automation Logic (Robust loop)
  useEffect(() => {
    let intervalId: any;

    if (autoDownload && downloadInterval > 0) {
      const checkAndDownload = async () => {
        const now = Date.now();
        const timeSinceLast = (now - lastDownloadRef.time) / 1000 / 60;

        if (timeSinceLast >= downloadInterval) {
          console.log('Running Auto PDF Download...');
          try {
            // Independent fetch to avoid state dependency
            const freshData = await ShiftService.getAll(selectedDate);
            const today = new Date().toLocaleDateString();
            const todaysShifts = freshData.filter(
              (s: any) => new Date(s.date).toLocaleDateString() === today,
            );

            if (todaysShifts.length > 0) {
              PDFService.generateDailyReport(todaysShifts, today);
              lastDownloadRef.time = now; // Update ref without triggering re-render
            }
          } catch (e) {
            console.error('Auto PDF Error', e);
          }
        }
      };

      intervalId = setInterval(checkAndDownload, 60000); // Check every minute
    }

    return () => clearInterval(intervalId);
  }, [autoDownload, downloadInterval, selectedDate, lastDownloadRef]);

  const handleManualDownload = () => {
    const today = new Date().toLocaleDateString();
    // Allow downloading filtered list OR all today's lists. Use filtered for manual to respect tabs?
    // User requested "de todos los movimientos", so let's offer a general download.
    // We will prioritize downloading ALL of TODAY's movements regardless of tab.
    const todaysShifts = shifts.filter((s) => new Date(s.date).toLocaleDateString() === today);

    if (todaysShifts.length > 0) {
      PDFService.generateDailyReport(todaysShifts, today);
    } else {
      // Fallback to current view if "today" is empty? Or just alert.
      alert('No hay movimientos con fecha de hoy para generar el reporte general.');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Header */}
      {/* Header */}
      <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white tracking-tight">
            <span>Gesti├│n de Turnos</span>
          </h1>
          <p className="text-slate-400">
            <span>Administra, aprueba y asigna turnos.</span>
          </p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-stretch md:items-center bg-slate-800/50 p-3 rounded-2xl border border-slate-700/50 w-full xl:w-auto">
          {/* Automation Controls */}
          <div className="flex items-center justify-between md:justify-start gap-2 px-2 border-b md:border-b-0 md:border-r border-slate-700 md:mr-2 pb-2 md:pb-0">
            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id="autoPDF"
                checked={autoDownload}
                onChange={(e) => setAutoDownload(e.target.checked)}
                className="w-5 h-5 rounded border-slate-600 bg-slate-700 text-primary-500 focus:ring-primary-500/50"
              />
              <label
                htmlFor="autoPDF"
                className="text-sm text-slate-300 cursor-pointer select-none font-medium"
              >
                Auto PDF
              </label>
            </div>

            {autoDownload && (
              <div className="flex items-center gap-1 animate-fade-in">
                <input
                  type="number"
                  min="1"
                  value={downloadInterval}
                  onChange={(e) => setDownloadInterval(Number(e.target.value))}
                  className="w-16 bg-slate-900 border border-slate-600 rounded-lg px-2 py-1 text-sm text-center focus:border-primary-500 outline-none"
                />
                <span className="text-xs text-slate-400">min</span>
              </div>
            )}
          </div>

          <div className="flex flex-col sm:flex-row gap-3 w-full">
            <button
              onClick={handleManualDownload}
              className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-xl transition-all shadow-lg shadow-primary-900/20 border border-primary-500 font-bold whitespace-nowrap"
              title="Descargar Reporte General del D├¡a"
            >
              <FileText className="w-5 h-5" />
              <span>Descargar General</span>
            </button>

            <div className="relative group flex-1">
              <input
                type="date"
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="w-full bg-slate-900 border border-slate-700 text-white rounded-xl px-4 py-2 text-sm focus:border-primary-500 focus:outline-none transition-all"
              />
            </div>

            <div className="relative group flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-primary-400" />
              <input
                type="text"
                placeholder="Buscar..."
