              />
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      {confirmAction && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm animate-fade-in">
          <div className="bg-slate-900 border border-slate-700 p-6 rounded-2xl w-full max-w-md shadow-2xl scale-100 animate-scale-in">
            <h3 className="text-xl font-bold text-white mb-2">
              <span>
                {confirmAction.type === 'reject' ? '┬┐Rechazar Turno?' : '┬┐Eliminar Turno?'}
              </span>
            </h3>
            <p className="text-slate-400 mb-6">
              <span>
                {confirmAction.type === 'reject'
                  ? '┬┐Est├ís seguro de que deseas rechazar y eliminar este turno?'
                  : 'Esta acci├│n eliminar├í el turno permanentemente y no se puede deshacer.'}
              </span>
            </p>

            <div className="flex gap-3">
              <button
                onClick={() => setConfirmAction(null)}
                className="flex-1 py-2.5 rounded-xl border border-slate-600 text-slate-300 hover:bg-slate-800 transition-colors font-medium"
              >
                <span>Cancelar</span>
              </button>
              <button
                onClick={executeConfirmAction}
                className="flex-1 py-2.5 rounded-xl bg-red-600 hover:bg-red-700 text-white shadow-lg shadow-red-900/20 transition-all font-bold"
              >
                <span>{confirmAction.type === 'reject' ? 'S├¡, Rechazar' : 'S├¡, Eliminar'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="border-b border-slate-800 flex gap-4 overflow-x-auto pb-2 custom-scrollbar">
        <TabButton
          name="Created"
          label="Pendientes"
          count={shifts.filter((s) => s.status === 'Created').length}
        />
        <TabButton
          name="Public"
          label="P├║blicos"
          count={shifts.filter((s) => s.status === 'Public').length}
        />
        <TabButton
          name="Assigned"
          label="Asignados"
          count={shifts.filter((s) => s.status === 'Assigned').length}
        />
      </div>

      {/* Content */}
      {error && (
        <div className="bg-red-500/10 border border-red-500/50 rounded-xl p-4 mb-6 flex items-center gap-3 animate-fade-in">
          <AlertCircle className="w-6 h-6 text-red-400" />
          <div className="flex-1">
            <h3 className="text-red-400 font-bold text-sm">Error de Conexi├│n</h3>
            <p className="text-red-300/80 text-sm">{error}</p>
          </div>
          <button
            onClick={loadShifts}
            className="px-3 py-1.5 bg-red-500/20 hover:bg-red-500/30 text-red-300 rounded-lg text-xs font-bold transition-colors"
          >
            Reintentar
          </button>
        </div>
      )}

      {isLoading ? (
        <div className="py-20 flex flex-col items-center justify-center text-slate-500 animate-fade-in">
          <Loader2 className="w-10 h-10 text-primary-500 animate-spin mb-4" />
          <span className="text-sm font-medium text-slate-400 animate-pulse">
            Cargando turnos en tiempo real...
          </span>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredShifts.length > 0 ? (
            filteredShifts.map((shift) => (
              <ShiftCard key={shift.id} shift={shift} variant="admin" onAction={handleAction} />
            ))
          ) : (
            <div className="col-span-full py-20 flex flex-col items-center justify-center text-slate-500 border border-dashed border-slate-800 rounded-2xl bg-slate-900/50">
              <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center mb-4 text-slate-600">
                <Filter className="w-6 h-6" />
              </div>
              <p>
                <span>No hay turnos en esta categor├¡a</span>
              </p>
            </div>
          )}
        </div>
      )}

      {/* Edit Modal */}
      {editingShift && (
        <EditShiftModal
          shift={editingShift}
          onClose={() => setEditingShift(null)}
          onSave={() => {
            loadShifts();
            setEditingShift(null);
          }}
        />
      )}

      {/* Assign Modal */}
      {assigningShiftId && (
        <AssignShiftModal
          onClose={() => setAssigningShiftId(null)}
          onAssign={handleAssignShift}
          currentAssigneeId={
            Number(shifts.find((s) => s.id === assigningShiftId)?.assignedTo ?? 0) as number
          }
        />
      )}
    </div>
  );
};

export default AdminShifts;

import { useState, useEffect } from 'react';
import { db } from '../../config/firebase';
import { collection, onSnapshot, query, where, Timestamp } from 'firebase/firestore';
import { Activity, Map as Users, AlertTriangle } from 'lucide-react';
import { MapContainer, TileLayer, CircleMarker, Popup } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';

const AdminStressTest = () => {
  // State for Simulation Metrics
  const [fleet, setFleet] = useState<any[]>([]);
  const [alerts, setAlerts] = useState<any[]>([]);
  const [metrics, setMetrics] = useState({
    activeDrivers: 0,
    requestsPerMinute: 0, // Simulated
    errors: 0,
    avgLatency: 45, // ms
  });

  // 1. Listen to Real-time Fleet
  useEffect(() => {
    // Query only recently updated (active in last 5 mins)
    const fiveMinsAgo = Timestamp.fromMillis(Date.now() - 5 * 60 * 1000);
    const q = query(collection(db, 'fleet_positions'), where('lastUpdate', '>', fiveMinsAgo));

    const unsub = onSnapshot(q, (snap) => {
      const drivers = snap.docs.map((d) => ({ id: d.id, ...d.data() }));
      setFleet(drivers);
      setMetrics((prev) => ({ ...prev, activeDrivers: drivers.length }));
    });
    return () => unsub();
  }, []);

  // 2. Listen to Alerts
  useEffect(() => {
    const q = query(collection(db, 'traffic_alerts'), where('expiresAt', '>', Timestamp.now()));
    const unsub = onSnapshot(q, (snap) => {
      setAlerts(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
    });
    return () => unsub();
  }, []);

  // 3. Simulate Load Metrics
  useEffect(() => {
    const interval = setInterval(() => {
      // Randomize load simulation numbers based on "Active Drivers"
      const baseLoad = Math.max(10, metrics.activeDrivers * 12); // ~12 req/min per driver
      const noise = Math.floor(Math.random() * 50);

      setMetrics((prev) => ({
        ...prev,
        requestsPerMinute: baseLoad + noise,
        avgLatency: 40 + Math.random() * 20,
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [metrics.activeDrivers]);

  return (
    <div className="h-full p-6 bg-slate-900 text-white overflow-hidden flex flex-col">
      <h1 className="text-2xl font-bold mb-6 flex items-center gap-2">
        <Activity className="text-red-500 animate-pulse" />
        Panel de Control de Carga (Stress Test Live)
      </h1>

      {/* METRICS CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
          <div className="text-slate-400 text-xs uppercase font-bold">Conductores Activos</div>
          <div className="text-3xl font-black text-blue-400 flex items-center gap-2">
            <Users className="w-6 h-6" />
            {metrics.activeDrivers}
          </div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
          <div className="text-slate-400 text-xs uppercase font-bold">Peticiones / Min</div>
          <div className="text-3xl font-black text-green-400 font-mono">
            {metrics.requestsPerMinute}
          </div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
          <div className="text-slate-400 text-xs uppercase font-bold">Latencia Promedio</div>
          <div className="text-3xl font-black text-yellow-400 font-mono">
            {Math.round(metrics.avgLatency)}ms
          </div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
          <div className="text-slate-400 text-xs uppercase font-bold">Alertas en V├¡a</div>
          <div className="text-3xl font-black text-red-500 flex items-center gap-2">
            <AlertTriangle className="w-6 h-6" />
            {alerts.length}
          </div>
        </div>
      </div>

      {/* LIVE FLEET MAP */}
      <div className="flex-1 bg-slate-800 rounded-2xl overflow-hidden border border-slate-700 relative">
        <MapContainer center={[-34.85, -56.16]} zoom={12} style={{ height: '100%', width: '100%' }}>
          <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

          {/* Fleet Markers */}
          {fleet.map((driver: any) => (
            <CircleMarker
              key={driver.id}
              center={[driver.lat, driver.lng]}
              radius={6}
              color="#3b82f6"
              fillColor="#3b82f6"
              fillOpacity={0.8}
            >
              <Popup className="bg-slate-900 text-white">
                <strong>L├¡nea {driver.line}</strong>
                <br />
                {driver.speed} km/h
              </Popup>
            </CircleMarker>
          ))}

          {/* Alert Markers */}
          {alerts.map((alert: any) => (
            <CircleMarker
              key={alert.id}
              center={[alert.lat, alert.lng]}
              radius={10}
              color="#ef4444"
              fillColor="#ef4444"
              fillOpacity={0.6}
            >
              <Popup>Alert: {alert.type}</Popup>
            </CircleMarker>
          ))}
        </MapContainer>

        <div className="absolute bottom-4 left-4 bg-slate-900/90 p-2 rounded text-xs text-slate-400 font-mono z-[1000]">
          System Status: NOMINAL
          <br />
          Database: CONNECTED
          <br />
          Simulation: ACTIVE (100 Users)
        </div>
      </div>
    </div>
  );
};

export default AdminStressTest;

import { useState, useEffect } from 'react';
import { Search, MessageCircle, ExternalLink } from 'lucide-react';

const AdminWhatsApp = () => {
  const [users, setUsers] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetch('/api/users')
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setUsers(data);
        } else {
          console.error('API Error:', data);
          setUsers([]);
        }
      })
      .catch((err) => {
        console.error('Error fetching users', err);
        setUsers([]);
      });
  }, []);

  const safeUsers = Array.isArray(users) ? users : [];
  const filteredUsers = safeUsers.filter(
    (u: any) =>
      u.fullName?.toLowerCase().includes(search.toLowerCase()) ||
      u.internalNumber?.includes(search),
  );

  const openWhatsAppWeb = () => {
    window.open('https://web.whatsapp.com', '_blank');
