import { useState, useEffect } from 'react';
import { collection, getDocs, query, where, orderBy } from 'firebase/firestore';
import { db } from '../../config/firebase';
import { gtfsExporter } from '../../services/gtfsExporter';
import {
  FileCheck, Download, AlertCircle, CheckCircle2,
  Clock, FileText, Calendar, Shield, TrendingUp
} from 'lucide-react';

// ÔöÇÔöÇÔöÇ Tipos ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

interface ReporteRequerido {
  id: string;
  nombre: string;
  descripcion: string;
  frecuencia: 'mensual' | 'trimestral' | 'anual' | 'evento';
  organismoReceptor: string;
  plazoLegal: string;
  ultimoEnvio?: string;
  estado: 'al_dia' | 'proximo' | 'vencido' | 'no_aplica';
  diasRestantes?: number;
  generadoAutomaticamente: boolean;
}

// ÔöÇÔöÇÔöÇ Datos de reportes requeridos por regulaci├│n Uruguay ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function calcularEstadoReporte(ultimoEnvio?: string, diaLimite = 3): {
  estado: ReporteRequerido['estado'];
  diasRestantes: number;
} {
  const hoy = new Date();
  const primerDiaMes = new Date(hoy.getFullYear(), hoy.getMonth(), 1);
  const fechaLimite = new Date(primerDiaMes);

  // Sumar d├¡as h├íbiles (aproximaci├│n simple: d├¡as h├íbiles Ôëê d├¡as corridos * 1.4)
  let diasHabilesContados = 0;
  const temp = new Date(primerDiaMes);
  while (diasHabilesContados < diaLimite) {
    temp.setDate(temp.getDate() + 1);
    const dow = temp.getDay();
    if (dow !== 0 && dow !== 6) diasHabilesContados++;
  }
  fechaLimite.setTime(temp.getTime());

  const diasRestantes = Math.ceil((fechaLimite.getTime() - hoy.getTime()) / 86400000);
  const yaEnviado = ultimoEnvio && ultimoEnvio.startsWith(
    `${hoy.getFullYear()}-${String(hoy.getMonth() + 1).padStart(2, '0')}`
  );

  if (yaEnviado) return { estado: 'al_dia', diasRestantes };
  if (diasRestantes < 0) return { estado: 'vencido', diasRestantes };
  if (diasRestantes <= 3) return { estado: 'proximo', diasRestantes };
  return { estado: 'proximo', diasRestantes };
}

