  }, [lineaParam]);

  useEffect(() => {
    if (
      lineasDisponibles.length > 0 &&
      selectedCodigo &&
      !lineasDisponibles.some((l) => l.id === selectedCodigo)
    ) {
      setSelectedCodigo(lineasDisponibles[0].id);
