        {/* 2. DATA GRID */}
        <div className="flex-1 overflow-hidden relative">
          {isParsing ? (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-950/80 z-20">
              <Loader2 className="w-10 h-10 text-blue-500 animate-spin mb-4" />
