    autoTable(doc, {
      head: [['Servicio', 'Desv├¡o Promedio', 'Carga Promedio', 'Puntaje']],
      body: tableBody,
      startY: 60,
      theme: 'grid',
      styles: { fontSize: 8 },
      headStyles: { fillColor: [22, 163, 74] }, // Emerald-600 color
    });

    doc.save(`reporte_inspectores_${new Date().toISOString().split('T')[0]}.pdf`);
  };

  if (loading)
