      {error && (
        <div className="mb-6 p-4 bg-red-500/10 border border-red-500/50 rounded-xl flex items-center gap-3 text-red-500">
          <AlertCircle className="w-5 h-5" />
          <p className="text-sm font-medium">{error}</p>
        </div>
      )}

      <form
        onSubmit={handleSubmit}
        className="glass-panel p-6 rounded-2xl border border-slate-700 space-y-6"
      >
        {/* Admin Only: Ceding User Override */}
        {currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin' ? (
          <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700 mb-6">
            <label className="text-sm font-bold text-yellow-400 block mb-2">
              <span>(Admin) ┬┐Qui├®n cede el turno?</span>
            </label>
            <input
              name="cedingInternalNumber"
              type="text"
              placeholder="Ingrese N┬░ Interno (Dejar vac├¡o si es propio)"
              onChange={handleChange}
              className="input-field bg-slate-900 border-yellow-500/30 text-white w-full placeholder:text-slate-600"
            />
            <p className="text-xs text-slate-500 mt-1">
              <span>
                Si ingresa un interno, el turno se registrar├í como creado por ese usuario (para
                balance).
              </span>
            </p>
          </div>
        ) : null}

        {/* Category Selection */}
        <div>
          <label className="text-sm font-medium text-slate-300 mb-2 block">
            <span>Categor├¡a del Turno</span>
          </label>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 gap-3">
            {categories.map((cat) => (
