      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {shifts.length > 0 ? (
            shifts.map((shift) => (
              <ShiftCard
                key={shift.id}
                shift={shift}
                variant="public"
                onAction={(action, id) => {
                  if (action === 'take') handleTakeShift(id);
                }}
