export const DatabaseBootstrapper = {
  /**
   * G├ëNESIS PROTOCOL
   * Ensures all collections exist and types are standardized.
   */
  runGenesis: async () => {
    const logs: string[] = [];
    const log = (m: string) => {
      console.log(`[GENESIS] ${m}`);
      logs.push(m);
    };

    try {
      if (!auth.currentUser) {
        log('Ôøö GENESIS ABORTED: User not authenticated. System initialization paused.');
        return { success: false, logs, error: 'Auth Required' };
      }

      log('­ƒÜÇ INITIATING GENESIS PROTOCOL...');

      // 1. MAESTRAS: Create/Verify Collections
      for (const colName of GENESIS_CONFIG.collections) {
        const colRef = collection(db, colName);
        const snapshot = await getDocs(query(colRef, limit(1)));

        if (snapshot.empty) {
          log(`ÔÜá´©Å Collection '${colName}' is EMPTY. Seeding defaults...`);

          // Check if we have defaults
          const defaults = (GENESIS_CONFIG.defaults as any)[colName];
          if (defaults) {
            for (const [key, val] of Object.entries(defaults)) {
              // If key starts with _, use it as ID, else auto-ID?
              // Actually defaults uses keys as IDs here for simplicity
              await setDoc(doc(db, colName, key), val as any);
              log(`   + Created default: ${colName}/${key}`);
            }
          } else {
            // Create a placeholder config doc to "wake up" the collection
            await setDoc(doc(db, colName, '_init'), {
              _genesis: true,
              createdAt: new Date().toISOString(),
            });
            log(`   + Created placeholder: ${colName}/_init`);
          }
        } else {
          log(`Ô£à Collection '${colName}' ONLINE (${snapshot.size}+ docs)`);
        }
      }

      // 2. INDEX CHECK (The "Trap")
      // We verify problematic queries to trigger the Link generation in Console
      log('­ƒöì VERIFYING INDEXES...');

      const checks = [
        { col: 'incidencias', orderBy: 'timestamp', desc: 'Incidents Time Sort' },
        { col: 'daily_shifts', orderBy: 'date', desc: 'Traffic Date Sort' },
        { col: 'alertas_trafico', orderBy: 'creado_en', desc: 'Alerts Sort' },
      ];

      for (const check of checks) {
        try {
          const q = query(collection(db, check.col), orderBy(check.orderBy, 'desc'), limit(1));
          await getDocs(q);
          log(`Ô£à Index OK: ${check.col} (${check.orderBy})`);
        } catch (e: any) {
          if (e.message.includes('requires an index')) {
            log(`ÔØî MISSING INDEX: ${check.col}`);
            log(`­ƒæë CLICK TO FIX: ${e.message.match(/https:\/\/\S+/)?.[0] || 'See Console'}`);
          } else {
            log(`ÔÜá´©Å Index Check Warning ${check.col}: ${e.message}`);
          }
        }
      }

      // 3. PHASE 1 SEEDING (Real Data from User Images)
      log('­ƒî▒ RUNNING PHASE 1 SEEDER (Real Summer 2026 Data)...');
      try {
        const seedResult = await seedServicesPhase1();
        log(
          `Ô£à Phase 1 Seed Complete: ${seedResult.count} services generated based on uploaded 'S├íbana'.`,
        );
      } catch (seedErr: any) {
        log(`ÔÜá´©Å Phase 1 Seed Warning: ${seedErr.message}`);
      }

      return { success: true, logs };
    } catch (e: any) {
      log(`­ƒöÑ GENESIS FAILED: ${e.message}`);
      return { success: false, logs, error: e.message };
    }
  },
};

import { db } from '../config/firebase';
import {
  collection,
  doc,
  serverTimestamp,
  writeBatch,
} from 'firebase/firestore';

export type IncidentType = 'MECANICA' | 'ACCIDENTE' | 'EVASION' | 'DEMORA';

export const IncidentService = {
  // Transactional Create: Incident Doc + Vehicle Status Update
  reportIncident: async (
    vehicleId: string,
    type: IncidentType,
    reporterId: string,
    reporterName: string,
  ) => {
    try {
      const batch = writeBatch(db);

      // 1. Create Incident Document (Auto-ID)
      const incidentRef = doc(collection(db, 'incidencias'));
      const statusMap: Record<IncidentType, string> = {
        MECANICA: 'EN_TALLER',
        ACCIDENTE: 'FUERA_DE_SERVICIO',
        EVASION: 'ACTIVO', // Evasi├│n doesn't necessarily stop the fleet
        DEMORA: 'ACTIVO', // Delay keeps it active but late
      };

      batch.set(incidentRef, {
        vehicleId,
        type,
        status: 'ABIERTO',
        priority: 'ALTA',
        createdAt: serverTimestamp(),
        reportedBy: {
          uid: reporterId,
          name: reporterName,
        },
        description: `Reporte r├ípido desde Dispatch Panel: ${type}`,
      });

      // 2. Update Vehicle Status
      const vehicleRef = doc(db, 'vehiculos', vehicleId);
      const newStatus = statusMap[type];

      // Only update status if it changes the operational state
      if (newStatus !== 'ACTIVO') {
        batch.update(vehicleRef, {
          state: newStatus,
          statusMessage: `Incidencia: ${type}`,
          lastUpdated: serverTimestamp(),
        });
      } else {
        // Just log valid last contact
        batch.update(vehicleRef, {
          lastUpdated: serverTimestamp(),
        });
      }

      await batch.commit();
      return { success: true, id: incidentRef.id };
    } catch (error) {
      console.error('Error reporting dispatch incident:', error);
      throw error;
    }
  },
};

import jsPDF from 'jspdf';
