      );
    } catch (e) {
      console.error('TrafficLinker Cache Error:', e);
    }
  },

  // 2. RESOLVE DRIVER
  resolveDriver(internalNumber: string) {
    const clean = String(internalNumber).trim();
    const found = _usersCache[clean];
    if (found) {
      const firstName = found.datos_personales?.nombre || found.firstName || 'Unknown';
      const lastName = found.datos_personales?.apellido || found.lastName || '';

      return {
        id: found.uid,
        internalNumber: clean,
        fullName: `${firstName} ${lastName}`,
        type: 'EFECTIVO' as const,
      };
    }

    return {
      id: 'UNKNOWN',
      internalNumber: clean,
      fullName: 'PERSONAL NO REGISTRADO',
      type: 'LISTA' as const, // Safer default for unknowns
    };
  },

  // 3. RESOLVE VEHICLE
  resolveVehicle(vehicleNumber: string) {
    const clean = String(vehicleNumber).trim();
    const found = _vehiclesCache[clean];

    if (found) {
      return {
        id: found.id,
        number: clean,
        status: (found.status === 'maintenance' ? 'BROKEN' : 'OK') as 'OK' | 'BROKEN',
      };
    }

    return {
      id: 'UNKNOWN',
      number: clean,
      status: 'UNKNOWN' as const,
    };
  },

  // 4. TRANSFORM ROTATION DATA -> DAILY SHIFT (The Magic)
  async processRotationImport(parsedData: ParsedData, date: string): Promise<DailyShift[]> {
    await this.preloadReferences();

    if (parsedData.type !== 'ROTACION') {
      console.warn('TrafficLinker: Wrong data type for Rotation Logic');
      return [];
    }

    return parsedData.services.map((svc) => {
      // "VehicleInternalNumber" from Excel usually maps to our Vehicle Number
      // "Driver" might not be in the Excel row depending on parser V2...
      // Wait, ParserV2 for Rotation returns: { vehicleInternalNumber, ... }
      // It currently does NOT extract Driver Legajo/Name explicitly in V2?
      // Need to check V2 parser output again. '' has vehicleInternalNumber, but no explicit 'driverCode'.
      // If the excel has driver info, we need to extract it.
      // Assuming for now Vehicle is the main link in the "Rotation" file provided (Salida).

      // NOTE: The current Rotation file provided (Matriz Salida) lists Service, Time, Line, and Vehicle.
      // It does NOT list Driver usually? The "Matriz de Salida" is usually "Car Assignment".
      // Driver assignment might come from "Distribution".
      // IF NO DRIVER: We create the shift with 'Unassigned' or link via Default Car Owner (future feature).

      const vehicle = this.resolveVehicle(svc.vehicleInternalNumber || '0000');

      return {
        id: `${date}_${svc.serviceNumber}`,
        date,
        serviceNumber: svc.serviceNumber,
        lineCode: svc.lineCode,
        startTime: svc.startTime,
        endTime: svc.endTime || '00:00',
        startLocation: 'SALIDA',
        endLocation: 'GUARDA',
        vehicle,
        driver: {
          id: 'UNASSIGNED',
          internalNumber: '???',
          fullName: 'SIN ASIGNAR',
          type: 'LISTA',
        },
        status: 'SCHEDULED',
      };
    });
  },
};

import {
  collection,
  getDocs,
  doc,
  writeBatch,
  Timestamp,
  } from 'firebase/firestore';
import { db } from '../config/firebase';
import type { DailyShift, ServiceDefinition } from '../types/traffic';
import type { ParsedData } from '../utils/ExcelParserV2';

// Cache for quick lookups
const _usersIndex: Record<string, { uid: string; name: string }> = {};
const _vehiclesIndex: Record<string, { id: string; status: string }> = {};
let _cacheLoaded = false;

export const TransitSeeder = {
  /**
   * 1. LOAD MASTER REFERENCE COLLECTIONS (Users & Vehicles)
   * Reads existing collections to enable linking.
   */
  async loadMasterIndices() {
    if (_cacheLoaded) return;

    console.log('TransitSeeder: Loading Master Indices...');
    try {
      // Users Index (by internalNumber/legajo)
      const usersSnap = await getDocs(collection(db, 'users'));
      usersSnap.forEach((d) => {
        const data = d.data();
        const legajo = String(data.datos_empresa?.legajo || data.internalNumber || '').trim();
        const name =
          `${data.datos_personales?.nombre || ''} ${data.datos_personales?.apellido || ''}`.trim();
        if (legajo) {
          _usersIndex[legajo] = { uid: d.id, name: name || 'Usuario Sin Nombre' };
        }
      });

      // Vehicles Index (by number)
      const vehiclesSnap = await getDocs(collection(db, 'vehicles'));
      vehiclesSnap.forEach((d) => {
        const data = d.data();
        const num = String(data.vehicleNumber || data.unitNumber || '').trim();
        if (num) {
          _vehiclesIndex[num] = { id: d.id, status: data.status || 'OK' };
        }
      });

      _cacheLoaded = true;
      console.log(
        `TransitSeeder: Indexed ${_usersIndex.length} users and ${_vehiclesIndex.length} vehicles.`,
      );
    } catch (e) {
      console.warn('TransitSeeder: Failed to load indices (Offline?)', e);
    }
  },

  /**
   * UNIVERSAL IMPORTER ROUTER
   * Decides what to do based on file type detected by ParserV2
   */
  async importUniversal(
    parsedData: ParsedData,
    forceDate?: string,
  ): Promise<{ success: boolean; message: string }> {
    await this.loadMasterIndices();

    const _timestamp = new Date();

    try {
      switch (parsedData.type) {
        case 'ROTACION':
          return await this.importDailyRotation(
            parsedData,
            forceDate || new Date().toISOString().split('T')[0],
          );

        case 'CARTON':
          return await this.importServiceDefinitions(parsedData); // Cartones = Definitions

        case 'BOLETIN': // Fallback for scheds
        case 'MATRIZ_COMPLEJA':
          return await this.importServiceDefinitions(parsedData); // Treat as definitions for now

        default:
          return { success: false, message: 'Tipo de archivo no reconocido por TransitSeeder.' };
      }
    } catch (error: any) {
      console.error('TransitSeeder Error:', error);
      return { success: false, message: `Error cr├¡tico: ${error.message}` };
    }
  },

  /** M├íximo de operaciones por batch (l├¡mite Firestore). */
  BATCH_SIZE: 500,

  /**
   * B. IMPORT SERVICE DEFINITIONS (Cartones)
   * Escribe en service_definitions y en colecci├│n cartones (esquema UCOT) en chunks de 500.
   */
  async importServiceDefinitions(parsedData: ParsedData) {
    const services = parsedData.services;
    if (!services.length) return { success: false, message: 'No services found.' };

    let count = 0;
    for (let offset = 0; offset < services.length; offset += this.BATCH_SIZE) {
      const chunk = services.slice(offset, offset + this.BATCH_SIZE);
      const batch = writeBatch(db);

      for (const svc of chunk) {
        const docRef = doc(db, 'service_definitions', String(svc.serviceNumber));
        const def: ServiceDefinition = {
          serviceNumber: svc.serviceNumber,
          lineCode: svc.lineCode,
          trips: (svc.fullSchedule || []).map((trip, i) => ({
            tripId: trip.id || `trip-${i}`,
            startTime: trip.startTime,
            endTime: '',
            direction: 'IDA',
          })),
          headers: svc.stops || [],
          rawMatrix: svc.fullSchedule || [],
        };
        batch.set(docRef, def);
        count++;
      }
      await batch.commit();
    }

    // 5.3 ÔÇö Escribir tambi├®n en colecci├│n cartones (id: servicioId_minuta). Minuta seg├║n d├¡a: HABILES | SABADEROS | FESTIVOS.
    const dayType = (parsedData as { dayType?: string }).dayType?.toUpperCase() ?? '';
    const minuta =
      dayType === 'SABADO'
        ? 'SABADEROS'
        : dayType === 'FESTIVO' || dayType === 'DOMINGO'
          ? 'FESTIVOS'
          : parsedData.type === 'CARTON'
            ? 'HABILES'
            : 'HABILES';
    let cartonesCount = 0;
    for (let offset = 0; offset < services.length; offset += this.BATCH_SIZE) {
      const chunk = services.slice(offset, offset + this.BATCH_SIZE);
      const batch = writeBatch(db);
      for (const svc of chunk) {
        const docId = `${svc.serviceNumber}_${minuta}`;
        let stopNames = (svc.stops || []).map((s: string) => String(s).trim()).filter(Boolean);
        const schedule = svc.fullSchedule || [];
        if (stopNames.length === 0 && schedule.length > 0) {
          const firstRow = schedule[0]?.checkpoints ?? [];
          stopNames = firstRow.map((_: string, i: number) => `Punto ${i + 1}`);
        }
        // Construcci├│n del array paradas: una entrada por columna (parada), tiempos = columna de cada viaje en HH:mm
        const paradas = stopNames.map((nombre: string, colIdx: number) => ({
          nombre,
          tiempos: schedule.map(
            (trip: { checkpoints?: string[] }) => trip.checkpoints?.[colIdx] ?? '--:--',
          ),
        }));
        const firstRow = svc.fullSchedule?.[0];
        const turnos = (svc.fullSchedule || []).slice(0, 3).map((trip, i) => ({
          numero: (i + 1) as 1 | 2 | 3,
          inicio: trip.startTime || '--:--',
          fin: (trip as { endTime?: string }).endTime || '--:--',
          duracion: '',
          primerPunto: paradas[0]?.nombre || '',
        }));
        batch.set(
          doc(db, 'cartones', docId),
          {
            servicio: String(svc.serviceNumber),
            linea: svc.lineCode || '',
            minuta,
            nombre: `Cart├│n ${svc.serviceNumber} ${minuta}`,
            paradas,
            turnos,
            totalHoras:
              svc.totalHours ||
              (svc.durationMinutes
                ? `${Math.floor(svc.durationMinutes / 60)}:${String(svc.durationMinutes % 60).padStart(2, '0')}`
                : ''),
            kilometros: svc.kilometers || '',
            temporada: 'VERANO_2026', // Requerido para filtro AdminCartones
            tipo_dia:
              dayType === 'SABADO'
                ? 'SABADO'
                : dayType === 'DOMINGO' || dayType === 'FESTIVO'
                  ? 'DOMINGO'
                  : 'HABIL',
            vigenciaDesde: Timestamp.now(),
            creadoEn: Timestamp.now(),
          },
          { merge: true },
        );
        cartonesCount++;
      }
      await batch.commit();
    }

    return {
      success: true,
      message: `Se definieron ${count} Servicios (service_definitions) y ${cartonesCount} cartones en colecci├│n cartones.`,
    };
  },

  /**
   * C. IMPORT DAILY ROTATION (Daily Shifts)
   * Procesa la totalidad de parsedData.services en chunks de 500 con writeBatch.
   */
  async importDailyRotation(parsedData: ParsedData, dateISO: string) {
    const services = parsedData.services;
    let count = 0;

    for (let offset = 0; offset < services.length; offset += this.BATCH_SIZE) {
      const chunk = services.slice(offset, offset + this.BATCH_SIZE);
      const batch = writeBatch(db);

      for (const svc of chunk) {
        const shiftId = `${dateISO}_${svc.serviceNumber}`;
        const docRef = doc(db, 'daily_shifts', shiftId);

        const vehicleInfo = _vehiclesIndex[String(svc.vehicleInternalNumber)];
        const vehicleData = vehicleInfo
          ? {
              id: vehicleInfo.id,
              number: svc.vehicleInternalNumber!,
              status: vehicleInfo.status as any,
            }
          : { id: 'UNKNOWN', number: svc.vehicleInternalNumber || '?', status: 'UNKNOWN' as any };

        const driverData = {
          id: 'UNASSIGNED',
          internalNumber: '?',
          fullName: 'SIN ASIGNAR',
          type: 'LISTA' as const,
          isMissing: false,
        };

        const shift: DailyShift = {
          id: shiftId,
          date: dateISO,
          serviceNumber: svc.serviceNumber,
          lineCode: svc.lineCode,
          startTime: svc.startTime,
          endTime: svc.endTime ?? '',
          startLocation: 'SALIDA',
          endLocation: svc.destination || 'GUARDA',
          vehicle: vehicleData,
          driver: driverData,
          status: 'SCHEDULED',
          createdAt: Timestamp.now(),
        };

        batch.set(docRef, shift);
        count++;
      }
      await batch.commit();
    }
    return {
      success: true,
      message: `Generados ${count} Turnos Diarios para ${dateISO}.`,
    };
  },
};

import {
  collection,
  doc,
  getDocs,
  setDoc,
  query,
  where,
  onSnapshot,
} from 'firebase/firestore';
import { db } from '../../config/firebase';
import type { AssignmentConflict } from './types';

const COL = 'assignment_conflicts';

function mapConflict(id: string, data: Record<string, unknown>): AssignmentConflict {
  return {
    id,
    type: (data?.type as 'Conflicto de Asignaci├│n') ?? 'Conflicto de Asignaci├│n',
    shiftId: data?.shiftId as string | undefined,
    serviceId: data?.serviceId as string | undefined,
    vehicleId: data?.vehicleId as string | undefined,
    driverId: data?.driverId as string | undefined,
    guardId: data?.guardId as string | undefined,
    driverName: data?.driverName as string | undefined,
    guardName: data?.guardName as string | undefined,
    vehicleInternalNumber: data?.vehicleInternalNumber as string | undefined,
    message: data?.message as string | undefined,
    status: (data?.status as 'open' | 'resolved') ?? 'open',
    createdAt: data?.createdAt as string | undefined,
    resolvedAt: data?.resolvedAt as string | undefined,
    ...data,
  } as AssignmentConflict;
}

export const AssignmentConflictService = {
  async getOpen(): Promise<AssignmentConflict[]> {
    const q = query(collection(db, COL), where('status', '==', 'open'));
    const snap = await getDocs(q);
    const list = snap.docs.map((d) => mapConflict(d.id, { ...d.data(), id: d.id }));
    list.sort((a, b) => (b.createdAt || '').localeCompare(a.createdAt || ''));
    return list;
  },

  subscribe(callback: (conflicts: AssignmentConflict[]) => void) {
    const q = query(collection(db, COL), where('status', '==', 'open'));
    return onSnapshot(q, (snap) => {
      const list = snap.docs.map((d) => mapConflict(d.id, { ...d.data(), id: d.id }));
      list.sort((a, b) => (b.createdAt || '').localeCompare(a.createdAt || ''));
      callback(list);
    });
  },

  async markResolved(id: string) {
    const ref = doc(db, COL, id);
    await setDoc(
      ref,
      { status: 'resolved', resolvedAt: new Date().toISOString() },
      { merge: true },
    );
  },

  /** Registra notificaci├│n de atraso/incidencia para inspector (sin conflicto de asignaci├│n). */
  async notifyInspector(params: {
    serviceId: string;
    message: string;
    vehicleId?: string;
    vehicleInternalNumber?: string;
  }) {
    const id = `notif_${params.serviceId}_${Date.now()}`;
    const ref = doc(db, COL, id);
    await setDoc(ref, {
      type: 'Notificaci├│n Inspector',
      serviceId: params.serviceId,
      message: params.message,
      vehicleId: params.vehicleId,
      vehicleInternalNumber: params.vehicleInternalNumber,
      status: 'open',
      createdAt: new Date().toISOString(),
    });
  },
};

import { collection, getDocs, doc, setDoc, getDoc, query, where } from 'firebase/firestore';
import { db } from '../../config/firebase';
import { getMasterLineas, getMasterServicios, getMasterServicioById } from '../../data/ucotMaster';
import type { Carton } from './types';

const LINEAS = 'lineas';
const SERVICIOS = 'servicios';
const SEASONS_COL = 'carton_seasons';
const SERVICE_DEFINITIONS = 'service_definitions';
const CARTONES = 'cartones';
const CARTONES_COMPLETADOS = 'cartones_completados';

/** ID de Servicio como clave primaria (Arquitectura CEO). Todo nace del JSON Maestro; Firestore solo guarda estado din├ímico. */

/** Mapea un doc de service_definitions al formato esperado por InspectorDashboard/InspectorCapture (id, linea, headers, rawMatrix, serviceNumber). */
function mapServiceDefToCartonShape(
  docId: string,
  data: Record<string, unknown>,
): Record<string, unknown> {
  const headers = ((data.headers as string[]) || []).map(
    (h: string | { id?: string; location?: string }, i: number) =>
      typeof h === 'string'
        ? { id: `stop-${i}`, location: h }
        : {
            id: (h as { id?: string }).id || `stop-${i}`,
            location: (h as { location?: string }).location || '',
          },
  );
  const rawMatrix = ((data.rawMatrix as Array<{ checkpoints?: string[] }>) || []).map(
    (r: { checkpoints?: string[] }) => ({
      checkpoints: r.checkpoints || [],
    }),
  );
  const serviceNumber = (data.serviceNumber as string) || docId;
  return {
    id: docId,
    serviceNumber,
    linea: data.lineCode || data.linea || '',
    headers,
    rawMatrix,
  };
}

/** Mapea un doc de colecci├│n cartones (esquema UCOT) al formato esperado por AdminCartones/InspectorDashboard. */
function mapCartonDocToShape(docId: string, data: Record<string, any>): Carton {
  const paradas = (data.paradas as Array<{ nombre: string; tiempos?: string[] }>) || [];
  const headers = paradas.map((p, i) => ({
    id: `stop-${i}`,
    location: (p.nombre || '').trim() || `Punto ${i + 1}`,
    isStop: true,
  }));

  // Re-pivot: Column-wise (DB) -> Row-wise (UI)
  const maxRows = Math.max(0, ...paradas.map((p) => p.tiempos?.length || 0));
  const rawMatrix = Array.from({ length: maxRows }, (_, rowIdx) => ({
    checkpoints: paradas.map((p) => (p.tiempos && p.tiempos[rowIdx]) || '--:--'),
  }));

  // Convert rawMatrix to 'rows' [{ id, times: { 'stop-0': 'HH:MM' } }] for DigitalCarton
  const rows = rawMatrix.map((r, rowIdx) => {
    const times: Record<string, string> = {};
    r.checkpoints.forEach((t, colIdx) => {
      times[`stop-${colIdx}`] = t;
    });
    return { id: `r-${rowIdx}`, times };
  });

  const servicioId =
    (data.servicio as string) || (data.serviceNumber as string) || docId.split('_')[0];

  return {
    id: docId,
    serviceNumber: servicioId,
    linea: data.linea || '',
    line: data.linea || '', // For AdminCartones s.line
    title: data.nombre || data.nombreServicio || `Serv ${servicioId}`,
    headers,
    rawMatrix,
    routeData: { headers, rows }, // Full compatibility for DigitalCarton load
    temporada: data.temporada as string,
    tipo_dia: data.tipo_dia as string,
  };
}

export const CartonService = {
  /**
   * L├¡neas desde JSON Maestro (fuente de verdad). Fallback a Firestore si el maestro no tiene datos.
   */
  getLineIdsFromMaster(): string[] {
    const lineas = getMasterLineas();
    if (lineas.length > 0)
      return lineas
        .map((l) => l.id)
        .filter(Boolean)
        .sort();
    return [];
  },

  /**
   * Devuelve los IDs de l├¡neas disponibles.
   * Origen: 1) JSON Maestro, 2) service_definitions, 3) cartones, 4) lineas.
   */
  async getLineIds(): Promise<string[]> {
    const fromMaster = this.getLineIdsFromMaster();
    if (fromMaster.length > 0) return fromMaster;

    const seen = new Set<string>();
    try {
      const defsSnap = await getDocs(collection(db, SERVICE_DEFINITIONS));
      defsSnap.docs.forEach((d) => {
        const lineCode = (d.data().lineCode as string) || (d.data().linea as string);
        if (lineCode) seen.add(String(lineCode).trim());
      });
    } catch {
      // ignore
    }
    if (seen.size > 0) return Array.from(seen).sort();

    try {
      const cartonesSnap = await getDocs(collection(db, CARTONES));
      cartonesSnap.docs.forEach((d) => {
        const linea = d.data().linea as string;
        if (linea) seen.add(String(linea).trim());
      });
    } catch {
      // ignore
    }
    if (seen.size > 0) return Array.from(seen).sort();

    const lineasSnap = await getDocs(collection(db, LINEAS));
    return lineasSnap.docs
      .map((d) => d.id)
      .filter(Boolean)
      .sort();
  },

  /**
   * Servicios desde JSON Maestro por l├¡nea. Clave primaria = servicioId.
   */
  getServiciosFromMaster(
    lineaId?: string,
  ): Array<{ id: string; linea: string; serviceNumber: string }> {
    const list = getMasterServicios(lineaId);
    return list.map((s) => ({
      id: s.servicioId,
      linea: s.linea,
      serviceNumber: s.serviceNumber ?? s.servicioId,
    }));
  },

  getServicioMasterById(servicioId: string) {
    return getMasterServicioById(servicioId);
  },

  async getAll(seasonOrLine?: string, dayType?: string): Promise<any[]> {
    // 1. Specific Line Filter (e.g. "300")
    if (seasonOrLine && !/^(VERANO|INVIERNO)/.test(seasonOrLine)) {
      const lineId = seasonOrLine;
      const fromMaster = getMasterServicios(lineId);
      if (fromMaster.length > 0) {
        return fromMaster.map((s) => ({
          id: s.servicioId,
          linea: s.linea,
          serviceNumber: s.serviceNumber ?? s.servicioId,
          headers: (s.puntosControl ?? []).map((p, i) => ({ id: `stop-${i}`, location: p })),
          rawMatrix: (s.horarios ?? []).map((h) => ({ checkpoints: h.filas ?? [] })),
        }));
      }

      try {
        let q = query(collection(db, CARTONES), where('linea', '==', lineId));
        if (dayType) q = query(q, where('tipo_dia', '==', dayType));
        const snap = await getDocs(q);
        if (!snap.empty) return snap.docs.map((d) => mapCartonDocToShape(d.id, d.data()));
      } catch {
        /* ignore */
      }

      const servRef = collection(db, LINEAS, lineId, SERVICIOS);
      const servSnap = await getDocs(servRef);
      return servSnap.docs.map((s) => ({ id: s.id, linea: lineId, ...s.data() }));
    }

    // 2. Global Seasonal/DayType Filter (Memory Filter to avoid Composite Index dependency)
    try {
      const q = query(collection(db, CARTONES), where('temporada', '==', seasonOrLine));
      const snap = await getDocs(q);
      let list = snap.docs.map((d) => mapCartonDocToShape(d.id, d.data())) as any[];

      if (dayType) {
        list = list.filter((c: Carton) => c.tipo_dia === dayType);
      }
      if (list.length > 0) return list;
    } catch (err) {
      console.error('[CartonService] Filter error:', err);
    }

    // 3. Absolute Fallback: All Cartones or Legacy Definitions
    try {
      const allSnap = await getDocs(collection(db, CARTONES));
      if (!allSnap.empty) {
        const all = allSnap.docs.map((d) => mapCartonDocToShape(d.id, d.data()));
        return all.slice(0, 200); // Limit total
      }

      const defsSnap = await getDocs(collection(db, SERVICE_DEFINITIONS));
      if (!defsSnap.empty)
        return defsSnap.docs.map((d) => mapServiceDefToCartonShape(d.id, d.data()));
    } catch (err) {
      console.error('[CartonService] Fallback error:', err);
    }

    return [];
  },

  async save(payload: Record<string, unknown>) {
    const lineId = String(payload.linea ?? payload.line ?? '300');
    const serviceId = String(payload.id ?? payload.serviceId ?? 'default');
    const ref = doc(db, LINEAS, lineId, SERVICIOS, serviceId);
    await setDoc(ref, payload, { merge: true });
  },

  async swapVehicle(serviceId: string, vehicleId: string) {
    const lineasSnap = await getDocs(collection(db, LINEAS));
    for (const lineDoc of lineasSnap.docs) {
      const ref = doc(db, LINEAS, lineDoc.id, SERVICIOS, serviceId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
        await setDoc(ref, { vehicleId }, { merge: true });
        return;
      }
    }
  },

  async getSuggestions(_seasonId: number): Promise<any[]> {
    return [];
  },

  /** Cartones f├¡sicos (1 pesta├▒a = 1 doc): grilla 2D desde cartones_completados. */
  async getCartonesFisicos(): Promise<any[]> {
    try {
      const snap = await getDocs(collection(db, CARTONES_COMPLETADOS));
      return snap.docs.map((d) => ({ id: d.id, ...d.data(), source: 'fisico' }));
    } catch {
      return [];
    }
  },

  async getCartonFisicoById(id: string): Promise<Record<string, unknown> | null> {
    const snap = await getDoc(doc(db, CARTONES_COMPLETADOS, id));
    if (!snap.exists()) return null;
    return { id: snap.id, ...snap.data(), source: 'fisico' };
  },

  /** Actualiza los tiempos de un cart├│n (edici├│n in-place). Escribe en cartones y, si existe, en service_definitions para que la recarga muestre los datos. */
  async updateCartonParadas(
    cartonDocId: string,
    paradas: Array<{ nombre: string; tiempos?: string[] }>,
    lineId?: string,
  ): Promise<void> {
    const cartonesRef = doc(db, CARTONES, cartonDocId);
    await setDoc(cartonesRef, { paradas, ...(lineId ? { linea: lineId } : {}) }, { merge: true });

    const defRef = doc(db, SERVICE_DEFINITIONS, cartonDocId);
    const defSnap = await getDoc(defRef);
    if (defSnap.exists()) {
      const headers = paradas.map((p, i) => ({
        id: (p.nombre || '').trim() || `stop-${i}`,
        location: (p.nombre || '').trim() || `Punto ${i + 1}`,
      }));
      const maxLen = Math.max(0, ...paradas.map((p) => p.tiempos?.length ?? 0));
      const rawMatrix = Array.from({ length: maxLen }, (_, rowIdx) => ({
        checkpoints: paradas.map((p) => p.tiempos?.[rowIdx] ?? '--:--'),
      }));
      await setDoc(defRef, { headers, rawMatrix }, { merge: true });
    }
  },
};

