/**
 * GPS Tracker Service ÔÇö TransformaFacil UCOT
 * ============================================
 * Alimenta la colecci├│n `viajes_activos` en Firestore en tiempo real.
 * Funciona desde la app del conductor (web PWA o Android/Capacitor).
 * Compatible con la red 5G/4G de Antel (reemplaza la red 2G ca├¡da).
 *
 * INSTALACI├ôN:
 * No requiere dependencias extra ÔÇö usa las ya instaladas:
 * - @capacitor/network (ya en package.json)
 * - firebase/firestore (ya configurado)
 *
 * USO:
 *   import { gpsTracker } from '../services/gpsTrackerService';
 *   gpsTracker.iniciar({ cocheId: '115', linea: '300', conductorId: 'user123' });
 *   gpsTracker.detener();
 */

import {
  doc,
  setDoc,
  serverTimestamp,
  GeoPoint,
  deleteDoc,
} from 'firebase/firestore';
import { db } from '../config/firebase';

// ÔöÇÔöÇÔöÇ Tipos ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface ConfigTrackerParams {
  cocheId: string;       // Ej: "115", "203"
  linea: string;         // Ej: "300a", "306b"
  conductorId: string;   // UID de Firebase Auth
  conductorNombre?: string;
  empresa?: string;      // "UCOT" por defecto
  intervaloMs?: number;  // Intervalo GPS en ms (por defecto 15000 = 15s)
}

export interface EstadoTracker {
  activo: boolean;
  cocheId: string | null;
  linea: string | null;
  ultimaPosicion: { lat: number; lng: number } | null;
  ultimaActualizacion: Date | null;
  error: string | null;
  totalActualizaciones: number;
}

// ÔöÇÔöÇÔöÇ Constantes ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const COL_VIAJES = 'viajes_activos';
const INTERVALO_DEFAULT_MS = 15_000; // 15 segundos
const TIMEOUT_GPS_MS = 10_000;       // 10s m├íximo para obtener posici├│n
const PRECISION_MIN_METROS = 100;    // Descartar posiciones muy imprecisas

// ÔöÇÔöÇÔöÇ Clase GPS Tracker ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

class GpsTrackerService {
  private watchId: number | null = null;
  private intervaloId: ReturnType<typeof setInterval> | null = null;
  private config: ConfigTrackerParams | null = null;
  private estado: EstadoTracker = {
    activo: false,
    cocheId: null,
    linea: null,
    ultimaPosicion: null,
    ultimaActualizacion: null,
    error: null,
    totalActualizaciones: 0,
  };
  private listeners: Array<(estado: EstadoTracker) => void> = [];
  private ultimaPosicionBuffer: { lat: number; lng: number } | null = null;

  // ÔöÇÔöÇ Suscripci├│n de estado para la UI ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  onEstadoCambia(callback: (estado: EstadoTracker) => void): () => void {
    this.listeners.push(callback);
    return () => {
      this.listeners = this.listeners.filter((l) => l !== callback);
    };
  }

  private emitirEstado() {
    const snap = { ...this.estado };
    this.listeners.forEach((l) => l(snap));
  }

  getEstado(): EstadoTracker {
    return { ...this.estado };
  }

  // ÔöÇÔöÇ Iniciar tracking ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async iniciar(params: ConfigTrackerParams): Promise<void> {
    if (this.estado.activo) {
      console.warn('[GPS] Ya hay un tracking activo. Deteniendo el anterior...');
      await this.detener();
    }

    if (!navigator.geolocation) {
      const msg = 'Geolocalizaci├│n no disponible en este dispositivo';
      this.estado.error = msg;
      this.emitirEstado();
      throw new Error(msg);
    }

    // Solicitar permiso expl├¡cito
    try {
      const permiso = await navigator.permissions.query({ name: 'geolocation' });
      if (permiso.state === 'denied') {
        throw new Error('Permiso de GPS denegado. Habilit├í la ubicaci├│n en configuraci├│n.');
      }
    } catch {
      // Algunos browsers no soportan permissions API, continuar igual
    }

    this.config = {
      empresa: 'UCOT',
      intervaloMs: INTERVALO_DEFAULT_MS,
      ...params,
    };

    this.estado = {
      activo: true,
      cocheId: params.cocheId,
      linea: params.linea,
      ultimaPosicion: null,
      ultimaActualizacion: null,
      error: null,
      totalActualizaciones: 0,
    };

    console.log(`[GPS] Iniciando tracking ÔÇö Coche ${params.cocheId}, L├¡nea ${params.linea}`);

    // Obtener posici├│n inicial inmediata
    await this.obtenerYPublicar();

    // Watch continuo con watchPosition (m├ís eficiente que polling en m├│vil)
    this.watchId = navigator.geolocation.watchPosition(
      (pos) => {
        this.ultimaPosicionBuffer = {
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
        };
      },
      (err) => {
        console.warn('[GPS] Error watchPosition:', err.message);
      },
      {
        enableHighAccuracy: true,
        maximumAge: 5_000,
        timeout: TIMEOUT_GPS_MS,
      },
    );

    // Publicar en Firestore cada intervalo
    const intervalo = this.config.intervaloMs ?? INTERVALO_DEFAULT_MS;
    this.intervaloId = setInterval(() => {
      void this.obtenerYPublicar();
    }, intervalo);

    this.emitirEstado();
  }

  // ÔöÇÔöÇ Obtener posici├│n y publicar en Firestore ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async obtenerYPublicar(): Promise<void> {
    if (!this.config) return;

    let lat: number;
    let lng: number;
    let precision: number;

    // Usar buffer de watchPosition si est├í disponible (m├ís r├ípido)
    if (this.ultimaPosicionBuffer) {
      lat = this.ultimaPosicionBuffer.lat;
      lng = this.ultimaPosicionBuffer.lng;
      precision = 0;
    } else {
      // Fallback: getCurrentPosition
      try {
        const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject, {
            enableHighAccuracy: true,
            maximumAge: 10_000,
            timeout: TIMEOUT_GPS_MS,
          });
        });
        lat = pos.coords.latitude;
        lng = pos.coords.longitude;
        precision = pos.coords.accuracy;
      } catch (err) {
        const msg = err instanceof GeolocationPositionError
          ? this.mensajeErrorGps(err.code)
          : 'Error desconocido de GPS';
        this.estado.error = msg;
        console.error('[GPS] Error obteniendo posici├│n:', msg);
        this.emitirEstado();
        return;
      }
    }

    // Descartar posiciones muy imprecisas
    if (precision > PRECISION_MIN_METROS && precision !== 0) {
      console.warn(`[GPS] Posici├│n descartada por baja precisi├│n: ${precision}m`);
      return;
    }

    // Publicar en Firestore
    try {
      const docId = this.config.cocheId;
      const ref = doc(db, COL_VIAJES, docId);

      await setDoc(ref, {
        cocheId: this.config.cocheId,
        codigoLinea: this.config.linea,
        conductorId: this.config.conductorId,
        conductorNombre: this.config.conductorNombre ?? 'Conductor',
        empresa: this.config.empresa ?? 'UCOT',
        posicion: new GeoPoint(lat, lng),
        updatedAt: serverTimestamp(),
        estado: 'en_servicio',
        // Datos extra ├║tiles para el dashboard
        velocidad: null,
        rumbo: null,
        pasajeros: null,
      }, { merge: true });

      this.estado.ultimaPosicion = { lat, lng };
      this.estado.ultimaActualizacion = new Date();
      this.estado.totalActualizaciones++;
      this.estado.error = null;

      console.log(
        `[GPS] Ô£ô Publicado ÔÇö Coche ${docId} @ [${lat.toFixed(5)}, ${lng.toFixed(5)}]`,
      );
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Error Firestore';
      this.estado.error = `Error al publicar: ${msg}`;
      console.error('[GPS] Error Firestore:', msg);
    }

    this.emitirEstado();
  }

  // ÔöÇÔöÇ Detener tracking ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async detener(): Promise<void> {
    if (this.watchId !== null) {
      navigator.geolocation.clearWatch(this.watchId);
      this.watchId = null;
    }

    if (this.intervaloId !== null) {
      clearInterval(this.intervaloId);
      this.intervaloId = null;
    }

    // Marcar veh├¡culo como inactivo en Firestore
    if (this.config?.cocheId) {
      try {
        const ref = doc(db, COL_VIAJES, this.config.cocheId);
        await setDoc(ref, {
          estado: 'fuera_de_servicio',
          updatedAt: serverTimestamp(),
        }, { merge: true });
        console.log(`[GPS] Veh├¡culo ${this.config.cocheId} marcado como fuera de servicio`);
      } catch (err) {
        console.warn('[GPS] No se pudo actualizar estado en Firestore:', err);
      }
    }

    this.estado = {
      activo: false,
      cocheId: null,
      linea: null,
      ultimaPosicion: null,
      ultimaActualizacion: null,
      error: null,
      totalActualizaciones: 0,
    };
    this.config = null;
    this.ultimaPosicionBuffer = null;

    console.log('[GPS] Tracking detenido');
    this.emitirEstado();
  }

  // ÔöÇÔöÇ Eliminar veh├¡culo de viajes_activos (fin de turno) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async finalizarServicio(cocheId: string): Promise<void> {
    try {
      await deleteDoc(doc(db, COL_VIAJES, cocheId));
      console.log(`[GPS] Veh├¡culo ${cocheId} eliminado de viajes_activos`);
    } catch (err) {
      console.error('[GPS] Error al finalizar servicio:', err);
    }
  }

  // ÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private mensajeErrorGps(code: number): string {
    switch (code) {
      case GeolocationPositionError.PERMISSION_DENIED:
        return 'Permiso de ubicaci├│n denegado. Habilit├í el GPS en configuraci├│n.';
      case GeolocationPositionError.POSITION_UNAVAILABLE:
        return 'Se├▒al GPS no disponible. Verific├í que el GPS est├® activo.';
      case GeolocationPositionError.TIMEOUT:
        return 'Tiempo de espera GPS agotado. Reintentando...';
      default:
        return 'Error desconocido de GPS';
    }
  }
}

// ÔöÇÔöÇÔöÇ Singleton exportado ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export const gpsTracker = new GpsTrackerService();

