// ÔöÇÔöÇÔöÇ Clase Exportador ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

class GTFSExporterService {

  // ÔöÇÔöÇ Generar feed completo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async generarFeed(): Promise<{
    agency: GTFSAgency[];
    routes: GTFSRoute[];
    stops: GTFSStop[];
    trips: GTFSTrip[];
    calendar: GTFSCalendar[];
    shapes: GTFSShape[];
  }> {
    // Intentar cargar l├¡neas desde Firestore
    let routes: GTFSRoute[] = [];
    let stops: GTFSStop[] = [];
    const trips: GTFSTrip[] = [];
    const shapes: GTFSShape[] = [];

    try {
      const snap = await getDocs(collection(db, 'lineas_ucot'));
      if (snap.size > 0) {
        snap.docs.forEach((doc) => {
          const data = doc.data() as Partial<LineaUCOT>;
          const routeId = doc.id;

          routes.push({
            route_id: routeId,
            agency_id: 'UCOT',
            route_short_name: String(data.codigo ?? routeId),
            route_long_name: String(data.nombre ?? ''),
            route_type: 3,
            route_color: 'F5A623',
            route_text_color: '000000',
            route_desc: '',
          });

          // Extraer paradas si existen
          if (data.paradas) {
            data.paradas.forEach((p, i) => {
              const stopId = `${routeId}_stop_${i}`;
              stops.push({
                stop_id: stopId,
                stop_code: String(i + 1),
                stop_name: p.nombre,
                stop_lat: String(p.lat),
                stop_lon: String(p.lng),
                stop_timezone: 'America/Montevideo',
              });
            });
          }

          // Extraer shape si existe
          if (data.recorrido) {
            const shapeId = `shape_${routeId}`;
            data.recorrido.forEach((pt, seq) => {
              shapes.push({
                shape_id: shapeId,
                shape_pt_lat: String(pt.lat),
                shape_pt_lon: String(pt.lng),
                shape_pt_sequence: String(seq),
              });
            });

            trips.push({
              route_id: routeId,
              service_id: 'LV',
              trip_id: `trip_${routeId}_LV`,
              trip_headsign: String(data.nombre ?? routeId),
              direction_id: '0',
              shape_id: shapeId,
            });
          }
        });
      } else {
        routes = LINEAS_FALLBACK;
      }
    } catch {
      routes = LINEAS_FALLBACK;
    }

    return {
      agency: [AGENCY_UCOT],
      routes,
      stops,
      trips,
      calendar: CALENDARIOS,
      shapes,
    };
  }

  // ÔöÇÔöÇ Convertir a CSV (formato GTFS) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private objetoACSV<T extends Record<string, unknown>>(datos: T[]): string {
    if (datos.length === 0) return '';
    const headers = Object.keys(datos[0]);
    const filas = datos.map((row) =>
      headers.map((h) => {
        const val = String(row[h] ?? '');
        return val.includes(',') ? `"${val}"` : val;
      }).join(','),
    );
    return [headers.join(','), ...filas].join('\n');
  }

  // ÔöÇÔöÇ Exportar como descarga de archivos ZIP (usando JSZip si disponible) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async exportarComoArchivos(): Promise<void> {
    const feed = await this.generarFeed();

    const archivos: Record<string, string> = {
      'agency.txt': this.objetoACSV(feed.agency as unknown as Record<string, unknown>[]),
      'routes.txt': this.objetoACSV(feed.routes as unknown as Record<string, unknown>[]),
      'stops.txt': this.objetoACSV(feed.stops as unknown as Record<string, unknown>[]),
      'trips.txt': this.objetoACSV(feed.trips as unknown as Record<string, unknown>[]),
      'calendar.txt': this.objetoACSV(feed.calendar as unknown as Record<string, unknown>[]),
      'shapes.txt': this.objetoACSV(feed.shapes as unknown as Record<string, unknown>[]),
    };

    // Descargar cada archivo por separado (sin dependencia de JSZip)
    for (const [nombre, contenido] of Object.entries(archivos)) {
      if (!contenido) continue;
      const blob = new Blob([contenido], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `gtfs_ucot_${nombre}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      await new Promise((r) => setTimeout(r, 300)); // Esperar entre descargas
    }
  }

  // ÔöÇÔöÇ Exportar como JSON (para API) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async exportarJSON(): Promise<string> {
    const feed = await this.generarFeed();
    return JSON.stringify({
      generatedAt: new Date().toISOString(),
      agency: 'UCOT',
      ...feed,
    }, null, 2);
  }
}

export const gtfsExporter = new GTFSExporterService();

/**
 * MaintenanceService ÔÇö Gesti├│n de Mantenimiento UCOT
 * ====================================================
 * Manejo completo de mantenimiento preventivo, correctivo y
 * alertas predictivas para la flota el├®ctrica Yutong.
 *
 * D├ôNDE COLOCAR: frontend/src/services/maintenanceService.ts
 *
 * USO:
 *   import { maintenanceService } from '../services/maintenanceService';
 *   const pendientes = await maintenanceService.getPendientes();
