export type AlertType = 'ACCIDENT' | 'TRAFFIC' | 'POLICE' | 'DETOUR' | 'WEATHER' | 'OTHER';

export interface TrafficAlert {
  id?: string;
  type: AlertType;
  lat: number;
  lng: number;
  description: string;
  reportedBy: string; // User ID
  reportedAt: any; // Timestamp
  expiresAt: any; // Timestamp
  line?: string; // Optional: Specific to a line
}

export const TrafficService = {
  // Report a new alert
  reportAlert: async (alert: Omit<TrafficAlert, 'id' | 'reportedAt' | 'expiresAt'>) => {
    try {
      const now = new Date();
      const expiration = new Date(now.getTime() + 2 * 60 * 60 * 1000); // Expires in 2 hours by default

      await addDoc(collection(db, 'traffic_alerts'), {
        ...alert,
        reportedAt: Timestamp.fromDate(now),
        expiresAt: Timestamp.fromDate(expiration),
      });
      return true;
    } catch (e) {
      console.error('Error reporting alert', e);
      return false;
    }
  },

  // Get Active Alerts (Real-time listener recommended instead)
  getActiveAlerts: async () => {
    try {
      const now = Timestamp.fromDate(new Date());
      const q = query(
        collection(db, 'traffic_alerts'),
        where('expiresAt', '>', now),
        orderBy('expiresAt', 'desc'),
      );
      const snap = await getDocs(q);
      return snap.docs.map((d) => ({ id: d.id, ...d.data() }));
    } catch (e) {
      console.error(e);
      return [];
    }
  },

  // ­ƒôí BROADCAST POSITION (For Admin Fleet View)
  broadcastPosition: async (
    uid: string,
    line: string,
    lat: number,
    lng: number,
    speed: number,
    heading: number,
  ) => {
    try {
      const { doc, setDoc, getFirestore } = await import('firebase/firestore');
      const db = getFirestore();

      await setDoc(
        doc(db, 'fleet_positions', uid),
        {
          line,
          lat,
          lng,
          speed,
          heading,
          lastUpdate: Timestamp.now(),
          status: 'ONLINE',
        },
        { merge: true },
      );
    } catch (e) {
      console.error('GPS Broadcast Error', e);
    }
  },

  // ­ƒòÁ´©Å FETCH COMPETITOR POSITIONS
  fetchCompetitorPositions: async (lines: string[]): Promise<any[]> => {
    try {
      const PROXY_BASE = 'https://us-central1-ucot-gestor-cloud.cloudfunctions.net/montevideoProxy';
      const endpoint = `api/transportepublico/buses?lines=${lines.join(',')}`;
      const url = `${PROXY_BASE}?endpoint=${encodeURIComponent(endpoint)}`;

      const response = await fetch(url);
      if (!response.ok) throw new Error('API Proxy Error');

      return await response.json();
    } catch (e) {
      console.error('Competitor Fetch Error', e);
      return [];
    }
  },
};

import { db } from '../config/firebase';
import {
  collection,
  getDocs,
  updateDoc,
  addDoc,
  serverTimestamp,
  GeoPoint,
  writeBatch,
} from 'firebase/firestore';

export class ChaosEngine {
  private static intervalId: NodeJS.Timeout | null = null;
  private static running = false;
  private static eventCallback: (msg: string) => void = (msg) => console.log(msg);

  static setCallback(cb: (msg: string) => void) {
    this.eventCallback = cb;
  }

  static start() {
    if (this.running) return;
    this.running = true;
    this.log('­ƒÜÇ [CHAOS ENGINE] Iniciando Simulaci├│n de Vida (24H)...');
    this.log('ÔÜá´©Å PRECAUCI├ôN: Estr├®s constante sobre DB Firestore');

    let cycles = 0;

    this.intervalId = setInterval(async () => {
      cycles++;
      try {
        // 1. GPS MOVEMENT (Heartbeat)
        await this.moveFleet();

        // 2. PASSENGER FLUX
        if (cycles % 2 === 0) await this.updatePassengers();

        // 3. RANDOM BREAKDOWN (Every 60 cycles ~ 5 mins in real time, but here every 5s * 60 = 5m? No, user said 5s heartbeat)
        // Let's make it faster for demo: Every 10 cycles (50s)
        if (cycles % 10 === 0) await this.triggerBreakdown();

        // 4. AUTO REPAIR (Every 5 cycles)
        if (cycles % 5 === 0) await this.attemptRepairs();

        this.log(`ÔÅ▒´©Å Ciclo ${cycles} completado. Sistema VIVO.`);
      } catch (e: any) {
        console.error('Chaos Error:', e);
        this.log(`ÔØî Error en Ciclo: ${e.message}`);
      }
    }, 5000); // 5 Seconds Heartbeat
  }

  static stop() {
    if (this.intervalId) clearInterval(this.intervalId);
    this.running = false;
    this.log('­ƒøæ [CHAOS ENGINE] Simulaci├│n Detenida.');
  }

  private static log(msg: string) {
    const time = new Date().toLocaleTimeString();
    this.eventCallback(`[${time}] ${msg}`);
  }

  // --- LOGIC ---

  private static async moveFleet() {
    const snapshot = await getDocs(collection(db, 'vehiculos'));
    const batch = writeBatch(db);
    let moved = 0;

    snapshot.forEach((docSnap) => {
      const data = docSnap.data();
      const currentGeo = data.ubicacion_actual || new GeoPoint(-34.9, -56.1);

      // Random Jitter (0.001 deg ~ 100m)
      const latchg = (Math.random() - 0.5) * 0.002;
      const lngchg = (Math.random() - 0.5) * 0.002;

      batch.update(docSnap.ref, {
        ubicacion_actual: new GeoPoint(currentGeo.latitude + latchg, currentGeo.longitude + lngchg),
        ultima_actualizacion: serverTimestamp(),
      });
      moved++;
    });

    if (moved > 0) {
      await batch.commit();
      // Optional: Reduce log noise
      // this.log(`­ƒø░´©Å GPS actualizado para ${moved} unidades.`);
    }
  }

  private static async updatePassengers() {
    const snapshot = await getDocs(collection(db, 'vehiculos'));
    const batch = writeBatch(db);

    snapshot.forEach((docSnap) => {
      const current = docSnap.data().pasajeros_actuales || 20;
      // + / - 5 pax
      let next = current + Math.floor(Math.random() * 10 - 4);
      if (next < 0) next = 0;
      if (next > 80) next = 80;

      batch.update(docSnap.ref, { pasajeros_actuales: next });
    });

    await batch.commit();
  }

  private static async triggerBreakdown() {
    // Find an OPERATIONAL vehicle
    // Firestore query or client filter (Client filter simpler for small fleet)
    const snapshot = await getDocs(collection(db, 'vehiculos'));
    const operational = snapshot.docs.filter(
      (d) => d.data().estado_operativo === 'ACTIVO' || !d.data().estado_operativo,
    );

    if (operational.length === 0) return;

    // Pick one
    const victim = operational[Math.floor(Math.random() * operational.length)];
    const carId = victim.id;

    const failures = [
      'Falla de Motor (Alta Temperatura)',
      'Neum├ítico Pinchado',
      'Fallas en Sistema El├®ctrico',
      'Aire Acondicionado Goteando',
    ];
    const desc = failures[Math.floor(Math.random() * failures.length)];

    // 1. Mark Vehicle TALLER
    await updateDoc(victim.ref, { estado_operativo: 'TALLER' });

    // 2. Create Incident
    await addDoc(collection(db, 'incidencias'), {
      coche_id: carId,
      descripcion: desc,
      prioridad: 'ALTA',
      estado: 'PENDIENTE',
      reportado_por: 'SYSTEM_CHAOS',
      fecha_reporte: serverTimestamp(),
    });

    this.log(`­ƒöÑ [CRITICO] Coche ${carId} reporta: ${desc}. Enviado a TALLER.`);
  }

  private static async attemptRepairs() {
    const snapshot = await getDocs(collection(db, 'vehiculos'));
    const broken = snapshot.docs.filter((d) => d.data().estado_operativo === 'TALLER');

    for (const car of broken) {
      // 50% chance to repair
      if (Math.random() > 0.5) {
        await updateDoc(car.ref, { estado_operativo: 'ACTIVO' });
        this.log(`Ô£à [TALLER] Coche ${car.id} reparado y devuelto a servicio.`);

        // TODO: Close related incidents? (Complex query, skipping for Speed)
      }
    }
  }
}

